function frontMatterBlockText(text: string) {
  if (!/^---\r?\n/.test(text)) return "";
  const lines = text.split(/\r?\n/);
  const endIndex = lines.findIndex((line, index) => index > 0 && line.trim() === "---");
  return endIndex > 0 ? lines.slice(0, endIndex + 1).join("\n") : "";
}

