      kind: item.kind,
      title: item.caption || item.label,
      line: item.line,
      end_line: item.end_line,
      source_file: item.source_file,
    });
  }
  for (const key of active.value.compile?.semantic.labels || []) {
    if (seen.has(key)) continue;
