const normalizedToolbarCollapsedRows = (ids: string[]) =>
  Array.from(new Set(ids.filter((id) => toolbarCollapseRowIds.includes(id))));
const hasExpandedToolbarRows = computed(() => toolbarCollapseRowIds.some((id) => !store.toolbarCollapsedRows.includes(id)));
const anyCommandToolbarsCollapsed = computed(() => toolbarCollapseRowIds.some((id) => store.toolbarCollapsedRows.includes(id)));
function isToolbarCollapsed(id: string) {
  return store.toolbarCollapsedRows.includes(id);
}
function toolbarRowLabel(id: string) {
  return toolbarCollapseRowDefinitions.find((row) => row.id === id)?.label || "Toolbar";
}
function showToolbarRow(id: string) {
  const current = new Set(store.toolbarCollapsedRows);
  if (!current.has(id)) {
    store.statusMessage = `${toolbarRowLabel(id)} toolbar is already visible`;
    return;
  }
  current.delete(id);
  store.toolbarCollapsedRows = normalizedToolbarCollapsedRows([...current]);
  store.statusMessage = `${toolbarRowLabel(id)} toolbar restored`;
}
function hideToolbarRow(id: string) {
  const current = new Set(store.toolbarCollapsedRows);
  current.add(id);
  store.toolbarCollapsedRows = normalizedToolbarCollapsedRows([...current]);
  store.statusMessage = `${toolbarRowLabel(id)} toolbar hidden; use the Toolbars hidden menu, floating restore button, hidden toolbars tray, or View > Toolbars to show it again`;
}
function toggleToolbarRow(id: string) {
  if (isToolbarCollapsed(id)) {
    showToolbarRow(id);
  } else {
    hideToolbarRow(id);
  }
}
function setAllCommandToolbarsCollapsed(collapsed: boolean) {
  store.toolbarCollapsedRows = collapsed ? [...toolbarCollapseRowIds] : [];
  store.statusMessage = collapsed
    ? "All toolbars hidden; use the Toolbars hidden menu, floating restore button, hidden toolbars tray, or View > Toolbars to show them again"
    : "All toolbars restored";
}
function maximizeWritingSpace() {
  if (!writingSpaceMaximized.value) {
    writingSpaceRestoreLayout.value = {
      mode: store.mode,
      sidebar: store.sidebar,
      toolbarDisplay: store.toolbarDisplay,
      toolbarTextSize: store.toolbarTextSize,
      toolbarCollapsedRows: [...store.toolbarCollapsedRows],
      splitSourcePanes: store.splitSourcePanes,
    };
  }
  writingSpaceMaximized.value = true;
  store.mode = "focus";
  store.toolbarDisplay = "icons";
  store.toolbarTextSize = 9;
  store.splitSourcePanes = false;
  setAllCommandToolbarsCollapsed(true);
  store.statusMessage = "Maximized writing space; use Restore writing in the editor workspace to return";
  void nextTick(() => editorView?.focus());
}
function restoreWritingSpace() {
  const snapshot = writingSpaceRestoreLayout.value;
  if (snapshot) {
    store.mode = snapshot.mode;
    store.sidebar = snapshot.sidebar;
    store.toolbarDisplay = snapshot.toolbarDisplay;
    store.toolbarTextSize = snapshot.toolbarTextSize;
    store.toolbarCollapsedRows = normalizedToolbarCollapsedRows(snapshot.toolbarCollapsedRows);
    store.splitSourcePanes = snapshot.splitSourcePanes;
  } else {
    setAllCommandToolbarsCollapsed(false);
  }
  writingSpaceMaximized.value = false;
  writingSpaceRestoreLayout.value = null;
  store.statusMessage = "Restored writing layout";
  void nextTick(() => editorView?.focus());
}
function toggleWritingSpaceMaximized() {
  if (writingSpaceMaximized.value) {
    restoreWritingSpace();
  } else {
    maximizeWritingSpace();
  }
}
