async function checkTtsRuntime() {
  store.saveTtsPreferences(store.ttsPreferences);
  ttsInspectionBusy.value = true;
  try {
    ttsInspectionReport.value = await invoke<NativeTtsInspectionResponse>("inspect_native_tts", {
      request: {
        supertonic_command: store.ttsPreferences.supertonicCommand,
      },
    });
    ttsStatus.value = ttsRuntimeSummary.value;
    store.statusMessage = "Checked text-to-speech runtime setup";
  } catch (error) {
    ttsStatus.value = error instanceof Error ? error.message : String(error);
    store.lastError = ttsStatus.value;
    store.statusMessage = "Text-to-speech runtime check failed";
  } finally {
    ttsInspectionBusy.value = false;
  }
}

function saveTtsModelDownloadAcknowledgement() {
  const plan = ttsModelDownloadPlan.value;
  if (plan) {
    store.ttsPreferences.supertonicModelStoragePath = plan.storagePath;
  }
  store.saveTtsPreferences(store.ttsPreferences);
  store.statusMessage = store.ttsPreferences.supertonicModelDownloadAcknowledged
    ? "Supertonic model download acknowledgement saved"
    : "Supertonic model download acknowledgement cleared";
}

async function downloadSelectedTtsModel() {
  const plan = ttsModelDownloadPlan.value;
  if (!plan) return;
  if (!plan.acknowledged) {
    ttsStatus.value = "Review the Supertonic model name, size, and storage location before starting the download.";
    store.statusMessage = ttsStatus.value;
    return;
  }
  store.ttsPreferences.supertonicModelStoragePath = plan.storagePath;
  store.saveTtsPreferences(store.ttsPreferences);
  ttsModelDownloadBusy.value = true;
  try {
    const response = await invoke<NativeTtsResponse>("download_tts_model", {
      request: {
        engine: plan.engine,
        command_path: store.ttsPreferences.supertonicCommand,
        model: plan.model,
        approximate_size: plan.approximateSize,
        storage_path: plan.storagePath,
        acknowledged: plan.acknowledged,
      },
    });
    ttsStatus.value = response.message;
    store.statusMessage = response.message;
  } catch (error) {
    ttsStatus.value = error instanceof Error ? error.message : String(error);
    store.lastError = ttsStatus.value;
    store.statusMessage = "TTS model download could not be started";
  } finally {
    ttsModelDownloadBusy.value = false;
  }
}

async function copyTtsModelDownloadCommand() {
  const plan = ttsModelDownloadPlan.value;
  if (!plan) return;
  const text = ttsModelDownloadClipboardText(plan);
  try {
    await navigator.clipboard?.writeText(text);
  } catch {
    // Clipboard access is optional in desktop smoke and restricted browser contexts.
  }
  store.statusMessage = "TTS model download details are ready to copy";
}

async function readTextAloud(scope: "selection" | "document") {
  const sourceText = textToReadAloud(scope);
  if (!sourceText) {
    ttsStatus.value = scope === "selection" ? "Select text in the editor before using Read selection." : "The active document is empty.";
    store.statusMessage = ttsStatus.value;
    return;
  }
  const text = readableSpeechText(sourceText);
  store.saveTtsPreferences(store.ttsPreferences);
  const plan = ttsModelDownloadPlan.value;
  if (plan && !plan.acknowledged) {
    ttsStatus.value = ttsModelAcknowledgementMessage(plan);
    store.statusMessage = ttsStatus.value;
    return;
  }
  ttsBusy.value = true;
  try {
    if (store.ttsPreferences.engine === "browser-speech") {
      speakWithBrowserSpeech(text);
      ttsStatus.value = `Reading ${scope === "selection" ? "selection" : "document"} with browser speech (${text.length} characters)`;
    } else {
      const response = await invoke<NativeTtsResponse>("read_text_aloud", {
        request: {
          engine: store.ttsPreferences.engine,
          text,
          voice: nativeTtsVoiceForPreferences(store.ttsPreferences),
          language: nativeTtsLanguageForPreferences(store.ttsPreferences),
          rate: nativeTtsRateForPreferences(store.ttsPreferences),
          command_path: store.ttsPreferences.engine === "supertonic-cli" ? store.ttsPreferences.supertonicCommand : undefined,
          speed: store.ttsPreferences.engine === "supertonic-cli" ? store.ttsPreferences.supertonicSpeed : undefined,
          model_download_acknowledged: plan?.acknowledged,
          model_storage_path: plan?.storagePath,
        },
      });
      ttsStatus.value = `${response.message} with ${selectedTtsEngineLabel(store.ttsPreferences.engine) || response.engine}`;
      ttsBusy.value = false;
    }
    store.statusMessage = ttsStatus.value;
  } catch (error) {
    ttsStatus.value = error instanceof Error ? error.message : String(error);
    store.lastError = ttsStatus.value;
    store.statusMessage = "Read aloud failed";
    ttsBusy.value = false;
  }
}

function readableSpeechText(text: string) {
  return text
    .replace(/^---[\s\S]*?---\s*/m, "")
    .replace(/```[\s\S]*?```/g, " code block omitted. ")
    .replace(/`([^`]+)`/g, "$1")
    .replace(/!\[([^\]]*)\]\([^)]+\)/g, "$1")
    .replace(/\[([^\]]+)\]\([^)]+\)/g, "$1")
    .replace(/^#{1,6}\s+/gm, "")
    .replace(/[*_~>#-]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function speakWithBrowserSpeech(text: string) {
  const speech = typeof window !== "undefined" ? window.speechSynthesis : null;
  if (!speech || typeof SpeechSynthesisUtterance === "undefined") {
    throw new Error("Browser speech synthesis is unavailable in this runtime. Use macOS Say or Supertonic in Settings.");
  }
  speech.cancel();
  const chunks = speechTextChunks(text);
  let index = 0;
  const speakNext = () => {
    const chunk = chunks[index];
    if (!chunk) {
      ttsBusy.value = false;
      ttsStatus.value = "Finished reading aloud";
      store.statusMessage = ttsStatus.value;
      return;
    }
    index += 1;
    const utterance = new SpeechSynthesisUtterance(chunk);
    utterance.lang = store.ttsPreferences.language;
    utterance.rate = store.ttsPreferences.rate;
    const voiceName = store.ttsPreferences.voice.trim().toLowerCase();
    const voice = voiceName ? speech.getVoices().find((candidate) => candidate.name.toLowerCase() === voiceName) : null;
    if (voice) utterance.voice = voice;
    utterance.onend = speakNext;
    utterance.onerror = () => {
      ttsBusy.value = false;
      ttsStatus.value = "Browser speech synthesis stopped before completion";
      store.statusMessage = ttsStatus.value;
    };
    speech.speak(utterance);
  };
  speakNext();
}

function speechTextChunks(text: string, maxChars = 3200) {
  const sentences = text.match(/[^.!?]+[.!?]+|\S[\s\S]*$/g) || [text];
  const chunks: string[] = [];
  let current = "";
  for (const sentence of sentences) {
    const next = [current, sentence.trim()].filter(Boolean).join(" ");
    if (next.length > maxChars && current) {
      chunks.push(current);
      current = sentence.trim();
    } else {
      current = next;
    }
  }
  if (current) chunks.push(current);
  return chunks.length ? chunks : [text];
}

async function stopReadingAloud() {
  if (typeof window !== "undefined") window.speechSynthesis?.cancel();
  await invoke<NativeTtsResponse>("stop_text_aloud").catch(() => null);
  ttsBusy.value = false;
  ttsStatus.value = "Stopped reading aloud";
  store.statusMessage = ttsStatus.value;
}

function openAgentWorkspace(seedInstruction = "") {
  if (seedInstruction.trim()) {
    agentInstruction.value = seedInstruction.trim();
    agentContextAnswers.value = "";
  } else if (!agentInstruction.value.trim()) {
    agentInstruction.value = "Create or improve this document, revise it for the audience, run review readiness, and prepare the right distribution package.";
  }
  buildAgentWorkspacePlan();
  agentWorkspaceOpen.value = true;
  store.statusMessage = "Opened AI agent workspace";
}
function closeAgentWorkspace() {
  agentWorkspaceOpen.value = false;
}
function applyAgentWorkflowPlaybook(playbook: AgenticWorkflowPlaybook) {
  agentInstruction.value = playbook.instruction;
  agentContextAnswers.value = "";
  buildAgentWorkspacePlan();
  store.statusMessage = `Loaded ${playbook.label} playbook`;
}
function agentPlaybookTargets(playbook: AgenticWorkflowPlaybook): ExportTarget[] {
  const text = [playbook.instruction, playbook.summary, ...playbook.expectedOutputs].join(" ").toLowerCase();
  const targets: ExportTarget[] = [];
  const patterns: Array<[ExportTarget, RegExp]> = [
    ["pdf", /\bpdf\b/],
    ["docx", /\bdocx|word\b/],
    ["html", /\bhtml|web\b/],
    ["blog", /\bblog\b/],
    ["substack", /\bsubstack|newsletter\b/],
    ["latex", /\blatex|tex\b/],
    ["google-docs", /\bgoogle docs?\b/],
    ["epub", /\bepub|ebook|e-book\b/],
    ["pptx", /\bpptx|slides?|deck\b/],
    ["markdown-bundle", /\bmarkdown bundle|source package\b/],
  ];
  for (const [target, pattern] of patterns) {
    if (pattern.test(text)) targets.push(target);
  }
  return targets;
}
function agentPlaybookFocus(playbook: AgenticWorkflowPlaybook) {
  const text = [playbook.id, playbook.label, playbook.summary, playbook.instruction, ...playbook.bestFor, ...playbook.expectedOutputs]
    .join(" ")
    .toLowerCase();
  if (/\b(substack|blog|publish|release notes|announcement|newsletter)\b/.test(text)) return "publishing";
  if (/\b(technical|latex|research|architecture|academic|paper)\b/.test(text)) return "technical";
  if (/\b(strategy|market|portfolio|research notes)\b/.test(text)) return "strategy";
  if (/\b(policy|sop|operating procedure|control|compliance|governance)\b/.test(text)) return "operations";
  if (/\b(proposal|grant|funding|client|statement of work)\b/.test(text)) return "proposal";
  if (/\b(revision|revise|rewrite|executive audience|humanization)\b/.test(text)) return "revision";
  if (/\b(approval|board|decision|risk|sign-off)\b/.test(text)) return "approval";
  return "approval";
}
function agentPlaybookFocusLabel(playbook: AgenticWorkflowPlaybook) {
  return agentPlaybookFocusOptions.find((option) => option.value === agentPlaybookFocus(playbook))?.label || "Workflow";
}
function syncAgentProviderProfile() {
  const profile = aiProviderProfiles.find((item) => item.id === agentProviderId.value) || aiProviderProfiles[0];
  agentProviderEndpoint.value = profile.endpoint;
  agentProviderModel.value = profile.model;
  agentProviderKeyEnv.value = aiProviderDefaultKeyEnv(profile.id);
  ollamaModelOptions.value = [];
  ollamaModelEndpoint.value = "";
  ollamaModelStatus.value = isOllamaProvider.value ? "Refresh to load installed Ollama models." : "";
  agentProviderPackage.value = null;
  agentProviderResult.value = null;
  localAgentHandoffResult.value = null;
  localAgentHandoffError.value = "";
  localAgentResponsePath.value = "";
  localAgentResponseImport.value = null;
}

function applyStoredAiProviderDefaults() {
  const defaults = store.aiProviderDefaults;
  const profile = providerProfileById(defaults.profileId);
  agentProviderId.value = defaults.profileId;
  agentProviderEndpoint.value = defaults.endpoint || profile.endpoint;
  agentProviderModel.value = defaults.model || profile.model;
  agentProviderKeyEnv.value = defaults.keyEnv || aiProviderDefaultKeyEnv(defaults.profileId);
}

function formatOllamaModelOption(model: OllamaModelSummary) {
  return [
    model.name,
    model.parameter_size,
    model.quantization_level,
    model.family ? `family ${model.family}` : "",
    model.size ? formatOllamaModelSize(model.size) : "",
  ].filter(Boolean).join(" | ");
}

function formatOllamaModelSize(bytes: number) {
  if (!Number.isFinite(bytes) || bytes <= 0) return "";
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  if (bytes < 1024 * 1024 * 1024) return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  return `${(bytes / (1024 * 1024 * 1024)).toFixed(1)} GB`;
}

function formatOllamaModelTimestamp(value: string) {
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return value;
  return parsed.toLocaleString();
}

function shouldSelectFirstOllamaModel(models: OllamaModelSummary[]) {
  if (!models.length) return false;
  const current = agentProviderModel.value.trim();
  if (!current) return true;
  if (models.some((model) => model.name === current)) return false;
  return current === currentAgentProviderProfile.value.model.trim();
}

function confirmOllamaModelSelection() {
  if (!isOllamaProvider.value) return;
  const model = selectedOllamaModel.value;
  if (model) {
    store.statusMessage = `Selected Ollama model ${model.name}`;
    return;
  }
  if (agentProviderModel.value.trim()) {
    store.statusMessage = `Keeping current Ollama model ${agentProviderModel.value.trim()} until it appears in the refreshed model list`;
  }
}

async function refreshOllamaModels() {
  if (!isOllamaProvider.value) {
    ollamaModelStatus.value = "Select an Ollama provider profile before listing models.";
    return;
  }
  const endpoint = agentProviderEndpoint.value.trim();
  if (!endpoint) {
    ollamaModelStatus.value = "Enter an Ollama endpoint before listing models.";
    return;
  }
  ollamaModelBusy.value = true;
  ollamaModelStatus.value = "Loading models from Ollama...";
  try {
    const response = await invoke<OllamaModelListResponse>("list_ollama_models", {
      request: {
        endpoint,
        auth_header: currentAgentProviderProfile.value.authHeader,
        api_key: agentProviderApiKey.value,
        key_env: agentProviderKeyEnv.value,
      },
    });
    ollamaModelOptions.value = response.models || [];
    ollamaModelEndpoint.value = response.endpoint;
    if (shouldSelectFirstOllamaModel(ollamaModelOptions.value) && ollamaModelOptions.value[0]) {
      agentProviderModel.value = ollamaModelOptions.value[0].name;
    }
    const warning = response.warnings?.[0] ? ` ${response.warnings[0]}` : "";
    const selection = selectedOllamaModel.value ? ` Selected ${selectedOllamaModel.value.name}.` : "";
    ollamaModelStatus.value = `Loaded ${response.count} Ollama model${response.count === 1 ? "" : "s"} from ${response.endpoint}.${selection}${warning}`;
    store.statusMessage = response.count
      ? `Loaded ${response.count} Ollama model${response.count === 1 ? "" : "s"}${selectedOllamaModel.value ? ` and selected ${selectedOllamaModel.value.name}` : ""}`
      : "Ollama returned no installed models";
  } catch (error) {
    ollamaModelOptions.value = [];
    ollamaModelEndpoint.value = "";
    ollamaModelStatus.value = appErrorText(error);
    store.lastError = ollamaModelStatus.value;
    store.statusMessage = "Could not load Ollama models";
  } finally {
    ollamaModelBusy.value = false;
  }
}

function saveAgentProviderDefaults() {
  store.saveAiProviderDefaults({
    profileId: agentProviderId.value,
    endpoint: agentProviderEndpoint.value,
    model: agentProviderModel.value,
    keyEnv: agentProviderKeyEnv.value,
  });
  agentProviderPackage.value = null;
  agentProviderResult.value = null;
  store.statusMessage = `Saved ${providerProfileById(agentProviderId.value).label} setup defaults without storing an API key`;
}

function syncGoogleIntegrationFields() {
  googleClientId.value = store.googleIntegration.clientId;
  googleAccountHint.value = store.googleIntegration.accountHint;
  googleScopesText.value = googleOAuthScopesText(store.googleIntegration.scopes);
  googleOfflineAccess.value = store.googleIntegration.requestOfflineAccess;
  googleTokenExpiresAt.value = store.googleIntegration.tokenExpiresAt;
}

function saveGoogleIntegrationSetup() {
  const preferences = normalizeGoogleIntegrationPreferences({
    clientId: googleClientId.value,
    accountHint: googleAccountHint.value,
    scopes: googleScopeList.value,
    requestOfflineAccess: googleOfflineAccess.value,
    lastAuthorizedAt: store.googleIntegration.lastAuthorizedAt,
    tokenExpiresAt: googleTokenExpiresAt.value,
  });
  store.saveGoogleIntegrationPreferences(preferences);
  googleScopesText.value = googleOAuthScopesText(preferences.scopes);
  store.statusMessage = "Saved Google Docs OAuth setup without storing an access token";
  return preferences;
}

function startGoogleAuthPolling() {
  if (googleAuthPollTimer) window.clearInterval(googleAuthPollTimer);
  googleAuthPollTimer = window.setInterval(() => {
    void pollGoogleSignIn();
  }, 1500);
}

function stopGoogleAuthPolling() {
  if (!googleAuthPollTimer) return;
  window.clearInterval(googleAuthPollTimer);
  googleAuthPollTimer = null;
}

async function startGoogleSignIn() {
  const preferences = saveGoogleIntegrationSetup();
  if (!preferences.clientId) {
    googleAuthStatus.value = "Add a Google desktop OAuth client ID before signing in";
    return;
  }
  googleAuthBusy.value = true;
  googleAuthStatus.value = "Opening Google sign-in in the system browser";
  googleAccessToken.value = "";
  googleRefreshToken.value = "";
  googleTokenScope.value = "";
  try {
    const session = await invoke<GoogleOAuthStartResponse>("start_google_oauth_sign_in", {
      request: {
        client_id: preferences.clientId,
        scopes: preferences.scopes,
        login_hint: preferences.accountHint || null,
        offline_access: preferences.requestOfflineAccess,
      },
    });
    googleAuthSession.value = session;
    googleAuthPollStartedAt.value = new Date().toISOString();
    try {
      await openUrl(session.authorization_url);
    } catch {
      window.open(session.authorization_url, "_blank", "noopener,noreferrer");
    }
    startGoogleAuthPolling();
    googleAuthStatus.value = "Complete Google sign-in in the browser, then return to NEditor";
  } catch (error) {
    googleAuthBusy.value = false;
    googleAuthStatus.value = appErrorText(error);
  }
}

async function pollGoogleSignIn() {
  const session = googleAuthSession.value;
  if (!session) return;
  try {
    const response = await invoke<GoogleOAuthCallbackResponse>("poll_google_oauth_sign_in", {
      stateId: session.state,
    });
    if (!response.received) {
      googleAuthStatus.value = "Waiting for Google browser callback";
      return;
    }
    stopGoogleAuthPolling();
    googleAuthBusy.value = false;
    if (response.error) {
      googleAuthStatus.value = `Google sign-in failed: ${response.error}`;
      googleAuthSession.value = null;
      return;
    }
    if (!response.code) {
      googleAuthStatus.value = "Google callback did not include an authorization code";
      googleAuthSession.value = null;
      return;
    }
    await exchangeGoogleAuthorizationCode(session, response.code);
  } catch (error) {
    stopGoogleAuthPolling();
    googleAuthBusy.value = false;
    googleAuthStatus.value = appErrorText(error);
  }
}

async function exchangeGoogleAuthorizationCode(session: GoogleOAuthStartResponse, code: string) {
  googleAuthBusy.value = true;
  googleAuthStatus.value = "Exchanging Google authorization code for a session token";
  try {
    const body = googleOAuthTokenRequestBody(session, googleClientId.value, code);
    const response = await fetch("https://oauth2.googleapis.com/token", {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body,
    });
    const token = (await response.json()) as GoogleOAuthTokenResponse;
    if (!response.ok || token.error || !token.access_token) {
      throw new Error(token.error_description || token.error || `Google token exchange failed with HTTP ${response.status}`);
    }
    const expiresAt = token.expires_in ? new Date(Date.now() + token.expires_in * 1000).toISOString() : "";
    googleAccessToken.value = token.access_token;
    googleRefreshToken.value = token.refresh_token || "";
    googleTokenScope.value = token.scope || session.scopes.join(" ");
    googleTokenExpiresAt.value = expiresAt;
    googleAuthSession.value = null;
    googleAuthPollStartedAt.value = "";
    store.saveGoogleIntegrationPreferences({
      clientId: googleClientId.value,
      accountHint: googleAccountHint.value,
      scopes: session.scopes,
      requestOfflineAccess: session.offline_access,
      lastAuthorizedAt: new Date().toISOString(),
      tokenExpiresAt: expiresAt,
    });
    googleAuthStatus.value = googleRefreshToken.value
      ? "Google session token and in-memory refresh token are ready for Docs and Drive actions"
      : "Google session token is ready; sign in again if it expires before Google returns a refresh token";
    store.statusMessage = googleRefreshToken.value
      ? "Google Docs sign-in complete; access and refresh tokens kept in session memory"
      : "Google Docs sign-in complete; access token kept in session memory";
  } catch (error) {
    googleAuthStatus.value = appErrorText(error);
  } finally {
    googleAuthBusy.value = false;
  }
}

async function refreshGoogleAccessTokenIfNeeded(force = false) {
  if (!googleAccessToken.value) return false;
  if (!force && !googleOAuthTokenNeedsRefresh(googleTokenExpiresAt.value)) return true;
  if (!googleRefreshToken.value) {
    throw new Error("Google access token is expired or near expiry. Sign in with Google again to continue Docs actions.");
  }
  googleAuthBusy.value = true;
  googleAuthStatus.value = "Refreshing Google session token";
  try {
    const body = googleOAuthRefreshTokenRequestBody(googleClientId.value, googleRefreshToken.value);
    const response = await fetch("https://oauth2.googleapis.com/token", {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body,
    });
    const token = (await response.json()) as GoogleOAuthTokenResponse;
    if (!response.ok || token.error || !token.access_token) {
      throw new Error(token.error_description || token.error || `Google token refresh failed with HTTP ${response.status}`);
    }
    const expiresAt = token.expires_in ? new Date(Date.now() + token.expires_in * 1000).toISOString() : "";
    googleAccessToken.value = token.access_token;
    if (token.refresh_token) googleRefreshToken.value = token.refresh_token;
    googleTokenScope.value = token.scope || googleTokenScope.value;
    googleTokenExpiresAt.value = expiresAt;
    store.saveGoogleIntegrationPreferences({
      clientId: googleClientId.value,
      accountHint: googleAccountHint.value,
      scopes: googleScopeList.value,
      requestOfflineAccess: googleOfflineAccess.value,
      lastAuthorizedAt: store.googleIntegration.lastAuthorizedAt,
      tokenExpiresAt: expiresAt,
    });
    googleAuthStatus.value = "Google session token refreshed";
    store.statusMessage = "Google session token refreshed in memory";
    return true;
  } finally {
    googleAuthBusy.value = false;
  }
}

async function refreshGoogleAccessTokenNow() {
  try {
    await refreshGoogleAccessTokenIfNeeded(true);
  } catch (error) {
    googleAuthStatus.value = appErrorText(error);
  }
}

async function googleApiResponseNeedsSessionRefresh(response: Response) {
  if (response.status === 401) return true;
  if (response.status !== 403) return false;
  const bodyText = await response.clone().text().catch(() => "");
  return googleApiAuthErrorNeedsRefresh(response.status, bodyText);
}

async function fetchGoogleWithSessionRetry(request: () => Promise<Response>, retryStatus: string) {
  let response = await request();
  if (!(await googleApiResponseNeedsSessionRefresh(response)) || !googleRefreshToken.value) {
    return response;
  }
  googleDocsImportStatus.value = retryStatus;
  await refreshGoogleAccessTokenIfNeeded(true);
  response = await request();
  return response;
}

async function copyGoogleAccessToken() {
  if (!googleAccessToken.value) return;
  try {
    await navigator.clipboard.writeText(googleAccessToken.value);
    googleAuthStatus.value = "Copied session-only Google access token";
  } catch {
    googleAuthStatus.value = "Google access token is ready in this session, but clipboard copy was unavailable";
  }
}

async function importCurrentDocumentToGoogleDocs() {
  if (!googleAccessToken.value) {
    googleDocsImportStatus.value = "Sign in with Google before importing";
    return;
  }
  flushEditorTextToStore();
  googleDocsImportBusy.value = true;
  googleDocsImportStatus.value = "Preparing Google Docs import package";
  googleDocsReadbackPreview.value = "";
  try {
    await refreshGoogleAccessTokenIfNeeded();
    const preparation = await invoke<GoogleDocsLiveImportPreparation>("prepare_google_docs_live_import", {
      request: {
        text: active.value.text,
        file_path: active.value.path,
        options: store.exportOptionsForActive(),
      },
    });
    const boundary = `neditor-${Date.now().toString(36)}-${Math.random().toString(36).slice(2)}`;
    const docxBytes = new Uint8Array(preparation.docx_bytes);
    googleDocsImportStatus.value = `Uploading ${preparation.file_name} to Google Docs`;
    const response = await fetchGoogleWithSessionRetry(
      () =>
        fetch(GOOGLE_DRIVE_UPLOAD_URL, {
          method: "POST",
          headers: {
            Authorization: `Bearer ${googleAccessToken.value}`,
            "Content-Type": `multipart/related; boundary=${boundary}`,
          },
          body: googleDocsMultipartUploadBody(preparation.file_name, docxBytes, boundary),
        }),
      "Refreshing Google session token and retrying Docs upload",
    );
    const uploaded = (await response.json()) as GoogleDriveImportResponse;
    if (!response.ok || uploaded.error || !uploaded.id) {
      throw new Error(uploaded.error?.message || `Google Docs import failed with HTTP ${response.status}`);
    }
    googleDocsLiveDocumentId.value = uploaded.id;
    googleDocsLiveDocumentUrl.value = uploaded.webViewLink || "";
    googleDocsImportStatus.value = `Imported ${uploaded.name || preparation.document_title} to Google Docs`;
    store.statusMessage = `Google Docs import complete: ${uploaded.name || preparation.document_title}`;
  } catch (error) {
    googleDocsImportStatus.value = appErrorText(error);
  } finally {
    googleDocsImportBusy.value = false;
  }
}

async function readBackGoogleDocsImport() {
  if (!googleAccessToken.value || !googleDocsLiveDocumentId.value) return;
  googleDocsImportBusy.value = true;
  googleDocsImportStatus.value = "Reading back Google Docs text";
  try {
    await refreshGoogleAccessTokenIfNeeded();
    const response = await fetchGoogleWithSessionRetry(
      () =>
        fetch(googleDriveExportTextUrl(googleDocsLiveDocumentId.value), {
          headers: { Authorization: `Bearer ${googleAccessToken.value}` },
        }),
      "Refreshing Google session token and retrying Docs readback",
    );
    const text = await response.text();
    if (!response.ok) {
      throw new Error(text || `Google Docs readback failed with HTTP ${response.status}`);
    }
    googleDocsReadbackPreview.value = text.slice(0, 4000);
    googleDocsImportStatus.value = "Google Docs readback complete";
    store.statusMessage = "Google Docs readback complete";
  } catch (error) {
    googleDocsImportStatus.value = appErrorText(error);
  } finally {
    googleDocsImportBusy.value = false;
  }
}

async function clearGoogleSession() {
  const sessionState = googleAuthSession.value?.state;
  stopGoogleAuthPolling();
  googleAuthBusy.value = false;
  googleAccessToken.value = "";
  googleRefreshToken.value = "";
  googleTokenScope.value = "";
  googleAuthSession.value = null;
  googleAuthPollStartedAt.value = "";
  googleTokenExpiresAt.value = "";
  googleDocsImportStatus.value = "";
  googleDocsLiveDocumentId.value = "";
  googleDocsLiveDocumentUrl.value = "";
  googleDocsReadbackPreview.value = "";
  if (sessionState) {
    try {
      await invoke("cancel_google_oauth_sign_in", { stateId: sessionState });
    } catch {
      // Clearing local session state is still correct if the transient loopback listener already ended.
    }
  }
  googleAuthStatus.value = "Cleared Google session token";
}

function appErrorText(error: unknown) {
  return error instanceof Error ? error.message : String(error);
}

function aiProviderDefaultKeyEnv(profileId: AiProviderProfileId) {
  if (profileId === "openai-compatible" || profileId === "codex-cli") return "OPENAI_API_KEY";
  if (profileId === "anthropic-compatible" || profileId === "claude-code-cli") return "ANTHROPIC_API_KEY";
  if (profileId === "gemini-compatible" || profileId === "google-antigravity-cli") return "GOOGLE_API_KEY";
  if (profileId === "ollama-cloud") return "OLLAMA_API_KEY";
  if (profileId === "ollama-local") return "";
  return "NEDITOR_AI_API_KEY";
}

function setDeepResearchTargetPages(value: number) {
  deepResearchTargetPages.value = clampInteger(Number(value), 1, 200);
}

function deepResearchSettings() {
  return normalizeDeepResearchSettings({
    topic: deepResearchTopic.value || active.value.compile?.semantic.title || active.value.title,
    documentType: deepResearchDocumentType.value,
    audience: deepResearchAudience.value,
    searchProvider: citationSearchProvider.value,
    searxngUrl: citationSearxngUrl.value,
    tavilyApiKey: citationTavilyApiKey.value,
    iterations: deepResearchIterationsTarget.value,
    resultsPerIteration: deepResearchResultsPerIteration.value,
    targetPages: deepResearchTargetPages.value,
    providerProfileId: agentProviderId.value,
    model: agentProviderModel.value,
    endpoint: agentProviderEndpoint.value,
    keyEnv: agentProviderKeyEnv.value,
  });
}

async function searchCitationSources(query = citationSearchQuery.value) {
  const trimmed = query.trim();
  if (!trimmed) {
    store.statusMessage = "Enter a citation search query";
    return [];
  }
  if (citationSearchProvider.value === "local-library" && !active.value.path) {
    store.statusMessage = "Save the document before searching the local source library";
    return [];
  }
  citationSearchBusy.value = true;
  try {
    const response = await invoke<{ results: DeepResearchSource[] }>("search_citation_sources", {
      request: {
        query: trimmed,
        provider: citationSearchProvider.value,
        searxng_url: citationSearxngUrl.value,
        tavily_api_key: citationTavilyApiKey.value,
        limit: deepResearchResultsPerIteration.value,
        document_path: active.value.path,
      },
    });
    citationSearchResults.value = rankDeepResearchSources(response.results || [], trimmed);
    store.statusMessage = `Found ${citationSearchResults.value.length} citation source candidate${citationSearchResults.value.length === 1 ? "" : "s"}`;
    return citationSearchResults.value;
  } catch (error) {
    store.lastError = appErrorText(error);
    store.statusMessage = "Citation search failed";
    return [];
  } finally {
    citationSearchBusy.value = false;
  }
}

async function saveCitationSourceToLibrary(
  source: DeepResearchSource,
  options: { insertBibliography?: boolean; silent?: boolean; forceRefresh?: boolean } = {},
) {
  if (!active.value.path) {
    if (!options.silent) store.statusMessage = "Save the document before downloading citation sources";
    return null;
  }
  citationSourceBusyUrl.value = source.url;
  try {
    const response = await invoke<CitationDownloadResult>("download_citation_source", {
      request: {
        document_path: active.value.path,
        url: source.url,
        title: source.title,
        snippet: source.snippet,
        source: source.source,
        fit_score: source.fitScore,
        fit_label: source.fitLabel,
        fit_reasons: source.fitReasons,
        force_refresh: options.forceRefresh || undefined,
      },
    });
    if (options.insertBibliography) insertBlock(response.bibliography_stub);
    citationSourceLibraryDir.value = response.source_dir;
    await refreshCitationSourceLibrary({ silent: true });
    const action = response.reused ? "Reused existing source" : "Downloaded source";
    if (!options.silent) {
      const suffix = options.insertBibliography ? " and inserted bibliography stub" : "";
      store.statusMessage = `${action} at ${response.relative_path}${suffix}`;
    }
    return response;
  } catch (error) {
    if (!options.silent) {
      store.lastError = appErrorText(error);
      store.statusMessage = "Citation source download failed";
    }
    return null;
  } finally {
    citationSourceBusyUrl.value = "";
  }
}

async function downloadCitationSource(source: DeepResearchSource) {
  await saveCitationSourceToLibrary(source, { insertBibliography: true });
}

async function redownloadCitationSource(source: CitationSourceLibraryItem) {
  const response = await saveCitationSourceToLibrary(
    {
      title: source.title,
      url: source.url,
      snippet: source.snippet || "",
      source: source.source || "Saved source",
      fitScore: source.fit_score,
      fitLabel: source.fit_label,
      fitReasons: source.fit_reasons || [],
    },
    { forceRefresh: true },
  );
  if (response) {
    store.statusMessage = `Re-downloaded source @${response.citation_key} at ${response.relative_path}`;
  }
}

function uniqueResearchSources(sources: DeepResearchSource[]) {
  const byUrl = new Map<string, DeepResearchSource>();
  for (const source of sources) {
    const url = source.url.trim();
    if (!url || byUrl.has(url)) continue;
    byUrl.set(url, source);
  }
  return Array.from(byUrl.values());
}

async function downloadAllCitationSources() {
  if (!active.value.path) {
    store.statusMessage = "Save the document before saving citation sources";
    return;
  }
  const sources = uniqueResearchSources(citationSearchResults.value);
  if (!sources.length) {
    store.statusMessage = "No citation search results to save";
    return;
  }
  citationSourceBulkBusy.value = true;
  let saved = 0;
  let failed = 0;
  try {
    for (const source of sources) {
      const response = await saveCitationSourceToLibrary(source, { insertBibliography: false, silent: true });
      if (response) saved += 1;
      else failed += 1;
    }
    await refreshCitationSourceLibrary({ silent: true });
    store.statusMessage = `Saved or reused ${saved}/${sources.length} source${sources.length === 1 ? "" : "s"}${failed ? `; ${failed} failed` : ""}`;
  } finally {
    citationSourceBulkBusy.value = false;
  }
}

async function refreshCitationSourceLibrary(options: { silent?: boolean } = {}) {
  if (!active.value.path) {
    if (!options.silent) store.statusMessage = "Save the document before refreshing the source library";
    return [];
  }
  citationSourceLibraryBusy.value = true;
  try {
    const response = await invoke<CitationSourceLibraryResponse>("list_citation_sources", {
      request: {
        document_path: active.value.path,
      },
    });
    citationSourceLibrary.value = response.sources || [];
    citationSourceLibraryDir.value = response.associated_dir;
    if (!options.silent) {
      store.statusMessage = `Loaded ${citationSourceLibrary.value.length} saved citation source${citationSourceLibrary.value.length === 1 ? "" : "s"}`;
    }
    return citationSourceLibrary.value;
  } catch (error) {
    store.lastError = appErrorText(error);
    if (!options.silent) store.statusMessage = "Could not load citation source library";
    return [];
  } finally {
    citationSourceLibraryBusy.value = false;
  }
}

function citationSourceBibliographyStub(source: CitationSourceLibraryItem) {
  const accessed = new Date().toISOString().slice(0, 10).split("-").map(Number);
  const note = `Downloaded source: ${source.relative_path}${source.sha256 ? ` | sha256 ${source.sha256}` : ""}`;
  return [
    "```bibliography",
    JSON.stringify([
      {
        id: source.citation_key,
        type: "webpage",
        title: source.title || source.citation_key,
        URL: source.url,
        accessed: { "date-parts": [accessed] },
        note,
      },
    ]),
    "```",
    "",
  ].join("\n");
}

function insertCitationSourceBibliography(source: CitationSourceLibraryItem) {
  insertBlock(citationSourceBibliographyStub(source));
  store.statusMessage = `Inserted bibliography entry for @${source.citation_key}`;
}

function citationSourceNeedsRecovery(source: CitationSourceLibraryItem) {
  return source.file_exists === false || source.hash_matches === false;
}

function insertCitationSourceReference(source: CitationSourceLibraryItem) {
  insertCitationReference(source.citation_key);
}

function insertCitationSourceLibraryAudit() {
  insertBlock(citationSourceLibraryAuditMarkdown(citationSourceLibrary.value));
  store.statusMessage = "Inserted source library audit";
}

async function copyCitationSourceLibraryAudit() {
  const audit = citationSourceLibraryAuditMarkdown(citationSourceLibrary.value);
  try {
    await navigator.clipboard?.writeText(audit);
    store.statusMessage = "Copied source library audit";
  } catch {
    store.statusMessage = "Source library audit is ready to copy";
  }
}

async function copyCitationSourcePath(source: CitationSourceLibraryItem) {
  const path = source.path || source.relative_path;
  try {
    await navigator.clipboard?.writeText(path);
    store.statusMessage = `Copied source path for @${source.citation_key}`;
  } catch {
    store.statusMessage = `Source path ready: ${path}`;
  }
}

async function revealCitationSource(source: CitationSourceLibraryItem) {
  try {
    await invoke("reveal_path", { path: source.path });
    store.statusMessage = `Revealed source file for @${source.citation_key}`;
  } catch (error) {
    store.lastError = appErrorText(error);
    store.statusMessage = "Could not reveal citation source file";
  }
}

function formatCitationSourceBytes(bytes: number) {
  if (!Number.isFinite(bytes) || bytes <= 0) return "0 B";
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}

async function saveDeepResearchSources(results: DeepResearchSource[], loopIndex: number) {
  if (!deepResearchSaveSources.value || !active.value.path) return 0;
  const sources = uniqueResearchSources(results).slice(0, deepResearchResultsPerIteration.value);
  if (!sources.length) return 0;
  let saved = 0;
  deepResearchStatus.value = `Saving ${sources.length} source document${sources.length === 1 ? "" : "s"} from research loop ${loopIndex}`;
  for (const source of sources) {
    const response = await saveCitationSourceToLibrary(source, { insertBibliography: false, silent: true });
    if (response) saved += 1;
  }
  if (saved) {
    deepResearchSavedSourceCount.value += saved;
    await refreshCitationSourceLibrary({ silent: true });
  }
  return saved;
}

function ensureDeepResearchQualityAudit(settings: ReturnType<typeof deepResearchSettings>, markdown: string, iterations: DeepResearchIteration[]) {
  if (/^##\s+Quality Assurance & Review Handoff\b/im.test(markdown)) return markdown;
  return `${markdown.trim()}\n\n${deepResearchQualityAuditMarkdown(settings, markdown, iterations)}`;
}

async function runDeepResearchDocumentCreation() {
  const settings = deepResearchSettings();
  if (!settings.topic) {
    store.statusMessage = "Enter a deep research topic";
    return;
  }
  deepResearchBusy.value = true;
  deepResearchDraft.value = "";
  deepResearchIterations.value = [];
  deepResearchSavedSourceCount.value = 0;
  try {
    for (let index = 1; index <= settings.iterations; index += 1) {
      deepResearchStatus.value = `Planning research query ${index}/${settings.iterations}`;
      let query = fallbackDeepResearchQuery(settings, deepResearchIterations.value);
      try {
        const queryResult = await executeDirectAiProviderPrompt(
          {
            profileId: settings.providerProfileId,
            endpoint: settings.endpoint,
            model: settings.model,
            keyEnv: settings.keyEnv,
            systemPrompt: "You generate precise web search queries for document research. Return only the query text.",
            userPrompt: deepResearchQueryPrompt(settings, deepResearchIterations.value),
          },
          agentProviderApiKey.value,
        );
        query = queryResult.markdown.replace(/^["'`]+|["'`]+$/g, "").split("\n")[0].trim() || query;
      } catch {
        query = fallbackDeepResearchQuery(settings, deepResearchIterations.value);
      }
      deepResearchStatus.value = `Searching ${settings.searchProvider}: ${query}`;
      const results = await searchCitationSources(query);
      await saveDeepResearchSources(results, index);
      deepResearchStatus.value = `Reflecting on ${results.length} source candidate${results.length === 1 ? "" : "s"}`;
      let summary = results.map((result) => `- ${result.title}: ${result.snippet || result.url}`).join("\n");
      let gaps = ["Download and inspect the most relevant source documents before approval."];
      try {
        const reflection = await executeDirectAiProviderPrompt(
          {
            profileId: settings.providerProfileId,
            endpoint: settings.endpoint,
            model: settings.model,
            keyEnv: settings.keyEnv,
            systemPrompt: "You summarize search results and identify knowledge gaps for a sourced document draft.",
            userPrompt: deepResearchReflectionPrompt(settings, query, results, deepResearchIterations.value),
          },
          agentProviderApiKey.value,
        );
        const parsed = parseReflection(reflection.markdown);
        summary = parsed.summary || summary;
        gaps = parsed.gaps.length ? parsed.gaps : gaps;
      } catch {
        summary = summary || "No usable search results were returned.";
      }
      deepResearchIterations.value = [
        ...deepResearchIterations.value,
        { index, query, results, summary, gaps },
      ];
    }
    deepResearchStatus.value = "Writing deep research draft";
    try {
      const draft = await executeDirectAiProviderPrompt(
        {
          profileId: settings.providerProfileId,
          endpoint: settings.endpoint,
          model: settings.model,
          keyEnv: settings.keyEnv,
          systemPrompt: "You create sourced Markdown documents from research logs. Return only Markdown.",
          userPrompt: deepResearchDraftPrompt(settings, deepResearchIterations.value, citationSourceLibrary.value),
        },
        agentProviderApiKey.value,
      );
      deepResearchDraft.value = draft.markdown;
    } catch {
      deepResearchDraft.value = fallbackResearchDraft(settings, deepResearchIterations.value, citationSourceLibrary.value);
    }
    const maxExpansionPasses = expansionPassBudget(settings);
    let stalledExpansionPasses = 0;
    for (let pass = 1; estimateMarkdownPages(deepResearchDraft.value) < settings.targetPages && pass <= maxExpansionPasses; pass += 1) {
      const currentPages = estimateMarkdownPages(deepResearchDraft.value);
      const remainingPages = pageShortfall(settings, deepResearchDraft.value);
      deepResearchStatus.value =
        `Expanding ${currentPages}/${settings.targetPages} pages; ${remainingPages} page${remainingPages === 1 ? "" : "s"} remaining (pass ${pass}/${maxExpansionPasses})`;
      try {
        const expanded = await executeDirectAiProviderPrompt(
          {
            profileId: settings.providerProfileId,
            endpoint: settings.endpoint,
            model: settings.model,
            keyEnv: settings.keyEnv,
            systemPrompt: "You expand sourced Markdown documents with substantive analysis. Return the full document only.",
            userPrompt: deepResearchExpansionPrompt(
              settings,
              deepResearchDraft.value,
              deepResearchIterations.value,
              currentPages,
              pass,
              maxExpansionPasses,
              citationSourceLibrary.value,
            ),
          },
          agentProviderApiKey.value,
        );
        const nextDraft = expanded.markdown.trim();
        if (!nextDraft) break;
        deepResearchDraft.value = nextDraft;
        const nextPages = estimateMarkdownPages(deepResearchDraft.value);
        stalledExpansionPasses = nextPages <= currentPages ? stalledExpansionPasses + 1 : 0;
        if (stalledExpansionPasses >= 2 && nextPages < settings.targetPages) {
          deepResearchStatus.value = `Expansion paused at about ${nextPages}/${settings.targetPages} pages because the provider stopped increasing length.`;
          break;
        }
      } catch {
        break;
      }
    }
    deepResearchStatus.value = "Running quality assurance and humanization review";
    const pagesBeforeQa = estimateMarkdownPages(deepResearchDraft.value);
    try {
      const reviewed = await executeDirectAiProviderPrompt(
        {
          profileId: settings.providerProfileId,
          endpoint: settings.endpoint,
          model: settings.model,
          keyEnv: settings.keyEnv,
          systemPrompt: "You are a document QA editor. Return a complete, source-grounded, human-review-ready Markdown document.",
          userPrompt: deepResearchQualityPrompt(
            settings,
            deepResearchDraft.value,
            deepResearchIterations.value,
            pagesBeforeQa,
            citationSourceLibrary.value,
          ),
        },
        agentProviderApiKey.value,
      );
      const reviewedMarkdown = reviewed.markdown.trim();
      const reviewedPages = estimateMarkdownPages(reviewedMarkdown);
      if (reviewedMarkdown && (reviewedPages >= pagesBeforeQa || reviewedPages >= settings.targetPages)) {
        deepResearchDraft.value = ensureDeepResearchQualityAudit(settings, reviewedMarkdown, deepResearchIterations.value);
      } else {
        deepResearchDraft.value = ensureDeepResearchQualityAudit(settings, deepResearchDraft.value, deepResearchIterations.value);
      }
    } catch {
      deepResearchDraft.value = ensureDeepResearchQualityAudit(settings, deepResearchDraft.value, deepResearchIterations.value);
    }
    const finalPages = estimateMarkdownPages(deepResearchDraft.value);
    const savedSourceSuffix = deepResearchSavedSourceCount.value
      ? `; saved or reused ${deepResearchSavedSourceCount.value} source document${deepResearchSavedSourceCount.value === 1 ? "" : "s"}`
      : "";
    const readyMessage = finalPages >= settings.targetPages
      ? `Deep research draft reached the ${settings.targetPages}-page target`
      : `Deep research draft reached about ${finalPages}/${settings.targetPages} pages; provider output limits prevented more useful expansion`;
    store.statusMessage = `${readyMessage}${savedSourceSuffix}`;
    deepResearchStatus.value = `${readyMessage}${savedSourceSuffix}`;
  } catch (error) {
    store.lastError = appErrorText(error);
    deepResearchStatus.value = "Deep research failed";
  } finally {
    deepResearchBusy.value = false;
  }
}

function insertDeepResearchDraft() {
  if (!deepResearchDraft.value.trim()) return;
  const reviewPackageMarkdown = deepResearchReviewPackageMarkdown(
    deepResearchSettings(),
    deepResearchDraft.value,
    deepResearchIterations.value,
    deepResearchDocumentOptions(),
  );
  applyAgentMarkdown(reviewPackageMarkdown, "append-packet");
  store.statusMessage = "Inserted deep research draft with bibliography, citations, evidence log, and source audit";
}

function deepResearchDocumentOptions() {
  const profile = store.businessProfile;
  return {
    savedSourceCount: deepResearchSavedSourceCount.value,
    bibliographySources: citationSourceLibrary.value,
    sourceLibraryAuditMarkdown: citationSourceLibrary.value.length
      ? citationSourceLibraryAuditMarkdown(citationSourceLibrary.value)
      : "",
    owner: profile.companyName || profile.fullName || profile.roleTitle || "",
    preparedBy: profile.fullName || profile.companyName || "",
    organization: profile.companyName || "",
  };
}

function openDeepResearchDraftAsDocument() {
  if (!deepResearchDraft.value.trim()) return;
  const title = deepResearchTopic.value.trim()
    ? `Deep Research - ${deepResearchTopic.value.trim()}`
    : "Deep Research Draft";
  const documentMarkdown = deepResearchDocumentMarkdown(
    deepResearchSettings(),
    deepResearchDraft.value,
    deepResearchIterations.value,
    deepResearchDocumentOptions(),
  );
  store.newDocumentFromText(documentMarkdown, title);
  store.sidebar = "review";
  store.statusMessage = `Opened ${title} as an editable Markdown document`;
}

function insertDeepResearchLog() {
  const log = formatDeepResearchLog(deepResearchIterations.value);
