}

function insertDeepResearchAuditPacket() {
  const packet = deepResearchAuditPacketMarkdown(
    deepResearchSettings(),
    deepResearchDraft.value || active.value.text,
    deepResearchIterations.value,
    deepResearchDocumentOptions(),
