    closeBrackets(),
    EditorView.contentAttributes.of({
      role: "textbox",
      "aria-label": label,
      "aria-multiline": "true",
      "data-keymap-mode": store.editorKeymapMode,
      "data-vim-mode": store.editorKeymapMode === "vim" ? vimInputMode.value : "",
      spellcheck: "true",
