    ? glossaryEntries.value.map((entry) => `| ${escapeMarkdownTableCell(entry.term)} | ${escapeMarkdownTableCell(entry.definition)} | review |`)
    : ["| No glossary terms detected | Add glossary definitions before review | open |"];
