    ...indexTerms.value.map((term) => `| ${escapeMarkdownTableCell(term)} | indexed | review |`),
    ...indexExclusionTerms.value.map((term) => `| ${escapeMarkdownTableCell(term)} | excluded | confirm exclusion |`),
  ];
