  store.statusMessage = `Removed ${term} from index exclusions`;
}

function formatFigureSnippet(position: FigureCropPosition) {
  return `![Figure alt](assets/figure.png){#fig:figure caption="Figure caption" fit="cover" position="${position}"}`;
}

function onFigureCropPositionChange(figure: FigureListItem, event: Event) {
  const value = (event.target as HTMLSelectElement | null)?.value;
  if (!isFigureCropPosition(value)) return;
  setFigureCropPosition(figure, value);
}

function setFigureCropPosition(figure: FigureListItem, position: FigureCropPosition) {
  if (!editorView || !canEditFigureSource(figure)) return;
  const line = editorView.state.doc.line(Math.max(1, Math.min(figure.line, editorView.state.doc.lines)));
  const withFit = upsertMarkdownAttribute(line.text, "fit", "cover");
  const updated = upsertMarkdownAttribute(withFit, "position", position);
  editorView.dispatch({
    changes: { from: line.from, to: line.to, insert: updated },
    selection: { anchor: line.from, head: line.from + updated.length },
  });
  editorView.focus();
}

function onFigureCropPointerDown(figure: FigureListItem, event: PointerEvent) {
  const element = event.currentTarget as HTMLElement | null;
  if (!element || !canEditFigureSource(figure)) return;
  element.setPointerCapture?.(event.pointerId);
  setFigureCropPosition(figure, figureCropPositionFromPointer(element, event));
}

function onFigureCropPointerMove(figure: FigureListItem, event: PointerEvent) {
  if (event.buttons !== 1) return;
  const element = event.currentTarget as HTMLElement | null;
  if (!element || !canEditFigureSource(figure)) return;
  setFigureCropPosition(figure, figureCropPositionFromPointer(element, event));
}

function onFigureCropKeydown(figure: FigureListItem, event: KeyboardEvent) {
  if (!canEditFigureSource(figure)) return;
  const current = normalizeFigureCropPosition(figure.position);
  const grid = figureCropPositionGrid[current];
  let next = grid;
  if (event.key === "ArrowUp") next = { ...grid, y: clampGridValue(grid.y - 1) };
  else if (event.key === "ArrowDown") next = { ...grid, y: clampGridValue(grid.y + 1) };
  else if (event.key === "ArrowLeft") next = { ...grid, x: clampGridValue(grid.x - 1) };
  else if (event.key === "ArrowRight") next = { ...grid, x: clampGridValue(grid.x + 1) };
  else if (event.key === "Home") next = { x: 0, y: 0 };
  else return;
  event.preventDefault();
  setFigureCropPosition(figure, figureCropPositionFromGrid(next.x, next.y));
}

function figureCropPositionFromPointer(element: HTMLElement, event: PointerEvent): FigureCropPosition {
  const rect = element.getBoundingClientRect();
  const x = rect.width > 0 ? (event.clientX - rect.left) / rect.width : 0.5;
  const y = rect.height > 0 ? (event.clientY - rect.top) / rect.height : 0.5;
  return figureCropPositionFromGrid(pointerGridValue(x), pointerGridValue(y));
}

function pointerGridValue(value: number): -1 | 0 | 1 {
  if (value < 1 / 3) return -1;
  if (value > 2 / 3) return 1;
  return 0;
}

function clampGridValue(value: number): -1 | 0 | 1 {
  if (value < 0) return -1;
  if (value > 0) return 1;
  return 0;
}

function figureCropPositionFromGrid(x: -1 | 0 | 1, y: -1 | 0 | 1): FigureCropPosition {
  const match = figureCropPositions.find((position) => {
    const point = figureCropPositionGrid[position];
    return point.x === x && point.y === y;
  });
  return match || "center";
}

function figureCropPreviewStyle(figure: FigureListItem): CSSProperties {
  const position = normalizeFigureCropPosition(figure.position);
  const point = figureCropPositionPoints[position];
  const style: CSSProperties = {
    backgroundPosition: `${point.x}% ${point.y}%`,
  };
  if (figure.src) {
    style.backgroundImage = `linear-gradient(rgba(15, 23, 42, 0.18), rgba(15, 23, 42, 0.18)), url("${escapeCssUrl(figure.src)}")`;
  }
  return style;
}

function figureCropPointStyle(position: FigureCropPosition): CSSProperties {
  const point = figureCropPositionPoints[position];
  return { left: `${point.x}%`, top: `${point.y}%` };
}

function figureCropReticleStyle(position: FigureCropPosition): CSSProperties {
  const point = figureCropPositionPoints[position];
  return { left: `${point.x}%`, top: `${point.y}%` };
}

function normalizeFigureCropPosition(value: string | null | undefined): FigureCropPosition {
  if (isFigureCropPosition(value || undefined)) return value as FigureCropPosition;
  return "center";
}

function escapeCssUrl(value: string) {
  return value.replace(/\\/g, "\\\\").replace(/"/g, '\\"');
}

function canEditFigureSource(figure: FigureListItem) {
  return !figure.source_file || !active.value.path || figure.source_file === active.value.path;
}

function upsertMarkdownAttribute(line: string, key: string, value: string) {
  const attribute = `${key}="${value}"`;
  const match = line.match(/\{([^{}]*)\}\s*$/);
  if (!match || match.index === undefined) return `${line}{${attribute}}`;
  const attrs = match[1];
  const pattern = new RegExp(`(^|\\s)${key}="[^"]*"`);
  const updatedAttrs = pattern.test(attrs)
    ? attrs.replace(pattern, (_token, prefix: string) => `${prefix}${attribute}`)
    : `${attrs.trim()} ${attribute}`.trim();
  return `${line.slice(0, match.index)}{${updatedAttrs}}`;
}

function isFigureCropPosition(value: string | undefined): value is FigureCropPosition {
  return Boolean(value && figureCropPositions.includes(value as FigureCropPosition));
}

function openTableEditor() {
  flushEditorTextToStore();
  store.sidebar = "tables";
  if (markdownTables.value.length && !tableDraft.value) {
    if (!loadTableAtCursor(true)) {
      loadSelectedTable();
      store.statusMessage = "Opened first source table for editing";
    }
  }
  if (!markdownTables.value.length && !tableDraft.value) createTableDraft();
}

function editorSelectionLineRange() {
  if (!editorView) return null;
  const selection = editorView.state.selection.main;
  return {
    fromLine: editorView.state.doc.lineAt(selection.from).number,
    toLine: editorView.state.doc.lineAt(selection.to).number,
  };
}

function loadTableAtCursor(silent = false) {
  flushEditorTextToStore();
  if (tableContextSwitchBlocked("loading another source table", silent)) return false;
  const range = editorSelectionLineRange();
  if (!range) {
    if (!silent) store.statusMessage = "Open the source editor and place the cursor inside a Markdown table";
    return false;
  }
  const index = findMarkdownTableIndexForLineRange(markdownTables.value, range.fromLine, range.toLine);
  if (index < 0) {
    if (!silent) store.statusMessage = "No Markdown table found at the current cursor or selection";
    return false;
  }
  selectedTableIndex.value = index;
  loadSelectedTable({ force: true });
  store.sidebar = "tables";
  const table = selectedTable.value;
  store.statusMessage = `Loaded source table from line ${table?.captionLine || table?.startLine || range.fromLine} for editing`;
  return true;
}

function tableContextSwitchBlocked(action: string, silent = false) {
  if (!tableDraftDirty.value) return false;
  if (!silent) store.statusMessage = `Apply or cancel the current table edit before ${action}.`;
  return true;
}

function selectTableForEditing(value: string) {
  if (tableContextSwitchBlocked("switching source tables")) return;
  const nextIndex = clampInteger(Number(value), 0, Math.max(0, markdownTables.value.length - 1));
  selectedTableIndex.value = nextIndex;
  loadSelectedTable({ force: true });
}

function goToSelectedTableSource(statusMessage = "") {
  const table = selectedTableForDraft.value;
  if (table) {
    void goToSourceTarget({
      line: table.captionLine || table.startLine,
      end_line: table.endLine,
      end_column: Number.MAX_SAFE_INTEGER,
    }).then(() => {
      if (statusMessage) store.statusMessage = statusMessage;
    });
    return;
  }
  const snapshot = tableSourceSnapshot.value;
  if (!snapshot || snapshot.documentId !== active.value.id) return;
  void goToSourceTarget({
    line: snapshot.startLine,
    end_line: snapshot.endLine,
    end_column: Number.MAX_SAFE_INTEGER,
  }).then(() => {
    if (statusMessage) store.statusMessage = statusMessage;
  });
}

function editSelectedTableInMarkdownText() {
  if (!selectedTableForDraft.value && !tableSourceSnapshot.value) {
    if (!loadTableAtCursor(true)) {
      if (tableContextSwitchBlocked("editing a Markdown table in text")) return;
      if (markdownTables.value.length) {
        loadSelectedTable({ force: true });
      } else {
        store.statusMessage = "Place the cursor inside a Markdown table or create one before editing table text";
        return;
      }
    }
  }
  goToSelectedTableSource("Selected the Markdown table text; direct source edits will refresh the visual grid when the pipe table is valid.");
}

function editorCursorLineColumn() {
  if (!editorView) return null;
  const selection = editorView.state.selection.main;
  const line = editorView.state.doc.lineAt(selection.from);
  return {
    lineNumber: line.number,
    columnNumber: selection.from - line.from + 1,
  };
}

function refreshTableCursorCellPreview(view = editorView) {
  if (!view) {
    tableCursorCellPreview.value = null;
    return;
  }
  const selection = view.state.selection.main;
  const line = view.state.doc.lineAt(selection.from);
  tableCursorCellPreview.value = findMarkdownTableCellAtPosition(
    view.state.doc.toString(),
    line.number,
    selection.from - line.from + 1,
  );
}

function moveMarkdownTableTextCell(view: EditorView, direction: -1 | 1) {
  const selection = view.state.selection.main;
  const line = view.state.doc.lineAt(selection.head);
  const target = findAdjacentMarkdownTableCellPosition(
    view.state.doc.toString(),
    line.number,
    selection.head - line.from + 1,
    direction,
  );
  if (!target) return false;
  const targetLine = view.state.doc.line(target.lineNumber);
  const position = Math.min(targetLine.to, targetLine.from + Math.max(0, target.columnNumber - 1));
  view.dispatch({
    selection: EditorSelection.cursor(position),
    scrollIntoView: true,
  });
  refreshTableCursorCellPreview(view);
  if (store.sidebar === "tables") syncTableEditorFromSourceCursor("selection");
  store.statusMessage = `Moved to table cell ${target.columnLabel}${target.rowKind === "header" ? " header" : target.rowIndex + 1}`;
  return true;
}

function syncTableEditorFromSourceCursor(reason: "selection" | "text-edit" = "selection") {
  const cursorCell = tableCursorCellPreview.value;
  if (
    !shouldSyncTableEditorFromSourceCursor({
      followSourceCursor: tableFollowSourceCursor.value,
      tablesSidebarActive: store.sidebar === "tables",
      draftDirty: tableDraftDirty.value,
      newDraft: isNewTableDraft.value,
      cursorTableIndex: cursorCell?.tableIndex ?? null,
      selectedTableIndex: selectedTableDraftMatch.value?.index ?? selectedTableIndex.value,
      hasDraft: Boolean(tableDraft.value),
    })
  ) {
    return false;
  }
  if (!cursorCell) return false;
  const draft = markdownTableToDraft(cursorCell.table);
  selectedTableIndex.value = cursorCell.tableIndex;
  isNewTableDraft.value = false;
  tableDraft.value = draft;
  rememberTableSource(cursorCell.table, draft);
  refreshTableSourceEditFromDraft();
  store.statusMessage =
    reason === "text-edit"
      ? "Loaded the typed Markdown table into the visual table editor"
      : "Loaded the table under the source cursor into the visual table editor";
  return true;
}

function loadTableTextCellAtCursor() {
  flushEditorTextToStore();
  if (tableContextSwitchBlocked("loading a table cell text edit")) return false;
  const cursor = editorCursorLineColumn();
  if (!cursor) {
    tableTextCellError.value = "Open the source editor and place the cursor inside a Markdown table cell.";
    store.statusMessage = "No Markdown table cell is available at the cursor";
    return false;
  }
  const edit = findMarkdownTableCellAtPosition(active.value.text, cursor.lineNumber, cursor.columnNumber);
  if (!edit) {
    tableTextCellEdit.value = null;
    tableTextCellValue.value = "";
    tableTextCellError.value = "Place the cursor in a Markdown table header or body cell, not the caption or separator row.";
    store.statusMessage = "No editable Markdown table cell found at the cursor";
    return false;
  }
  tableTextCellEdit.value = edit;
  tableTextCellValue.value = edit.value;
  tableTextCellError.value = "";
  selectedTableIndex.value = edit.tableIndex;
  loadSelectedTable({ force: true });
  store.sidebar = "tables";
  store.statusMessage = `Loaded table cell ${edit.columnLabel}${edit.rowKind === "header" ? " header" : edit.rowIndex + 1} for text editing`;
  return true;
}

function applyTableTextCellEdit() {
  const edit = tableTextCellEdit.value;
  if (!edit) return;
  flushEditorTextToStore();
  if (tableDraftDirty.value) {
    tableTextCellError.value = "Apply or cancel the current table edit before writing a table cell directly into the Markdown text.";
    store.statusMessage = "Table cell text edit is waiting for the current table draft";
    return;
  }
  const currentLineCell = findMarkdownTableCellAtPosition(active.value.text, edit.lineNumber, 1);
  if (!currentLineCell || edit.columnIndex >= currentLineCell.cellCount) {
    tableTextCellError.value = "The original table row is no longer an editable Markdown table row.";
    store.statusMessage = "Reload the table cell from the current source text";
    return;
  }
  const nextText = replaceMarkdownTableCellInText(active.value.text, edit, tableTextCellValue.value);
  store.updateText(nextText);
  void nextTick(() => syncEditorViewFromActiveDocument());
  const refreshed = findMarkdownTableCellAtPosition(nextText, edit.lineNumber, 1);
  if (refreshed) {
    selectedTableIndex.value = refreshed.tableIndex;
    loadSelectedTable({ force: true });
  }
  tableTextCellEdit.value = { ...edit, value: tableTextCellValue.value };
  tableTextCellError.value = "";
  store.statusMessage = `Updated Markdown table cell ${edit.columnLabel}${edit.rowKind === "header" ? " header" : edit.rowIndex + 1}`;
}

function goToTableTextCellSource() {
  const edit = tableTextCellEdit.value;
  if (!edit) return;
  void goToSourceTarget({
    line: edit.lineNumber,
    end_line: edit.lineNumber,
    column: 1,
    end_column: Number.MAX_SAFE_INTEGER,
  }).then(() => {
    store.statusMessage = `Selected Markdown row for table cell ${edit.columnLabel}`;
  });
}

function focusTableGrid() {
  tableEditorGrid.value?.focus();
  store.statusMessage = "Focused the visual table grid";
}

function focusTableSourceEditor() {
  tableSourceEditor.value?.focus();
  tableSourceEditor.value?.select();
  store.statusMessage = "Focused the editable Markdown source block";
}

async function insertTableDraftInMarkdownText() {
  if (!isNewTableDraft.value && tableContextSwitchBlocked("inserting a starter table in text")) return;
  const draft = normalizeTableDraft(isNewTableDraft.value && tableDraft.value ? tableDraft.value : createDefaultTableDraft());
  const issues = validateTableDraft(draft);
  if (issues.some((issue) => issue.severity === "error")) {
    store.statusMessage = "Fix table validation errors before inserting table text";
    return;
  }
  const serialized = serializeMarkdownTable(draft);
  const insertedSourceText = serialized.join("\n");
  insertTableAtCursor(serialized);
  await nextTick();
  isNewTableDraft.value = false;
  const updatedTables = parseMarkdownTables(active.value.text);
  let insertedTableIndex = -1;
  for (let index = updatedTables.length - 1; index >= 0; index -= 1) {
    if (tableSourceText(active.value.text, updatedTables[index]) === insertedSourceText) {
      insertedTableIndex = index;
      break;
    }
  }
  selectedTableIndex.value = insertedTableIndex >= 0 ? insertedTableIndex : Math.max(0, updatedTables.length - 1);
  const insertedTable = updatedTables[selectedTableIndex.value];
  tableDraft.value = draft;
  if (insertedTable) {
    tableSourceSnapshot.value = createTableSourceSnapshot(active.value.text, active.value.id, selectedTableIndex.value, insertedTable, draft);
    refreshTableSourceEditFromDraft();
    goToSelectedTableSource("Inserted a Markdown table and selected it for direct text editing");
    return;
  }
  tableSourceSnapshot.value = null;
  refreshTableSourceEditFromDraft();
  store.statusMessage = "Inserted a Markdown table";
}

function rememberTableSource(table: MarkdownTable, draft: TableDraft) {
  tableSourceSnapshot.value = createTableSourceSnapshot(active.value.text, active.value.id, selectedTableIndex.value, table, draft);
}

function refreshTableSourceEditFromDraft() {
  tableSourceEditText.value = tableDraft.value ? tableDraftMarkdownPreview.value : "";
  tableSourceEditError.value = "";
  tableSourceEditDirty.value = false;
  tableSourceEditLiveSynced.value = false;
}

function markTableSourceEditDirty() {
  tableSourceEditDirty.value = true;
  tableSourceEditError.value = "";
  tableSourceEditLiveSynced.value = false;
  void nextTick(() => {
    if (!tableSourceEditDirty.value) return;
    syncTableDraftFromSourceText({ canonicalize: false, clearDirty: false, reportInvalid: false, statusMessage: "" });
  });
}

function syncTableDraftFromSourceText(options: { canonicalize?: boolean; clearDirty?: boolean; reportInvalid?: boolean; statusMessage?: string } = {}) {
  const canonicalize = options.canonicalize ?? true;
  const clearDirty = options.clearDirty ?? true;
  const reportInvalid = options.reportInvalid ?? true;
  const parsed = tableDraftFromMarkdownSource(tableSourceEditText.value);
  if (!parsed) {
    tableSourceEditLiveSynced.value = false;
    if (reportInvalid) {
      tableSourceEditError.value = "Enter a valid Markdown pipe table with a header row and separator row.";
      store.statusMessage = "Markdown table source could not be parsed";
    }
    return false;
  }
  tableDraft.value = parsed.draft;
  if (canonicalize) tableSourceEditText.value = parsed.sourceText;
  tableSourceEditError.value = "";
  tableSourceEditLiveSynced.value = true;
  if (clearDirty) tableSourceEditDirty.value = false;
  if (options.statusMessage !== "") store.statusMessage = options.statusMessage || "Updated visual table grid from Markdown source text";
  return true;
}

function updateTableDraftFromSourceText() {
  return syncTableDraftFromSourceText();
}

function applyTableSourceEdit(forceSourceOverwrite = false) {
  if (!updateTableDraftFromSourceText()) return;
  applyTableDraft(forceSourceOverwrite);
}

function loadSelectedTable(options: { force?: boolean } = {}) {
  if (!options.force && tableContextSwitchBlocked("loading another source table")) return false;
  if (markdownTables.value.length && selectedTableIndex.value >= markdownTables.value.length) {
    selectedTableIndex.value = markdownTables.value.length - 1;
  }
  const table = selectedTable.value;
  isNewTableDraft.value = false;
  if (!table) {
    tableDraft.value = null;
    tableSourceSnapshot.value = null;
    refreshTableSourceEditFromDraft();
    return true;
  }
  const draft = markdownTableToDraft(table);
  tableDraft.value = draft;
  rememberTableSource(table, draft);
  refreshTableSourceEditFromDraft();
  return true;
}

function reloadTableDraftFromSource() {
  if (!selectedTableForDraft.value && tableSourceSnapshot.value && tableSourceSnapshot.value.documentId === active.value.id) {
    store.statusMessage = "The source table is not currently parseable; fix the Markdown text or apply the draft over source";
    return;
  }
  syncSelectedTableIndexToDraftMatch();
  loadSelectedTable({ force: true });
  store.statusMessage = "Reloaded table editor from the current Markdown source table";
}

function syncSelectedTableIndexToDraftMatch() {
  const match = selectedTableDraftMatch.value;
  if (!match) return null;
  if (selectedTableIndex.value !== match.index) selectedTableIndex.value = match.index;
  return match;
}

function createTableDraft() {
  if (tableContextSwitchBlocked("creating another table")) return;
  isNewTableDraft.value = true;
  tableSourceSnapshot.value = null;
  tableDraft.value = createDefaultTableDraft();
  refreshTableSourceEditFromDraft();
}

function applyTableDraft(forceSourceOverwrite = false) {
  flushEditorTextToStore();
  if (!isNewTableDraft.value && !selectedTable.value && markdownTables.value.length) {
    selectedTableIndex.value = clampInteger(selectedTableIndex.value, 0, markdownTables.value.length - 1);
  }
  const table = selectedTableForDraft.value;
  const draft = tableDraft.value;
  if (!draft) return;
  const issues = validateTableDraft(draft);
  if (issues.some((issue) => issue.severity === "error")) {
    store.statusMessage = "Fix table validation errors before applying";
    return;
  }
  const normalizedDraft = normalizeTableDraft(draft);
  const serialized = serializeMarkdownTable(normalizedDraft);
  if (table && !isNewTableDraft.value) {
    if (tableDraftSourceChanged.value && !forceSourceOverwrite) {
      store.statusMessage = "Markdown source changed; reload the table or explicitly apply the draft over the current source table";
      return;
    }
    const tableIndex = selectedTableDraftMatch.value?.index ?? selectedTableIndex.value;
    const replacement = replaceMarkdownTableInText(active.value.text, table, normalizedDraft);
    store.updateText(replacement.text);
    void nextTick(() => syncEditorViewFromActiveDocument());
    store.statusMessage = `Updated source table at lines ${replacement.startLine}-${replacement.endLine}`;
    tableSourceSnapshot.value = {
      documentId: active.value.id,
      tableIndex,
      startLine: replacement.startLine,
      endLine: replacement.endLine,
      sourceText: serialized.join("\n"),
      draftMarkdown: serialized.join("\n"),
    };
  } else if (!isNewTableDraft.value) {
    const snapshot = tableSourceSnapshot.value;
    if (forceSourceOverwrite && snapshot && snapshot.documentId === active.value.id) {
      const replacement = replaceMarkdownTableSnapshotInText(active.value.text, snapshot, normalizedDraft);
      store.updateText(replacement.text);
      void nextTick(() => syncEditorViewFromActiveDocument());
      store.statusMessage = `Replaced source table range ${replacement.startLine}-${replacement.endLine}`;
      tableSourceSnapshot.value = {
        documentId: active.value.id,
        tableIndex: selectedTableIndex.value,
        startLine: replacement.startLine,
        endLine: replacement.endLine,
        sourceText: serialized.join("\n"),
        draftMarkdown: serialized.join("\n"),
      };
    } else {
      store.statusMessage = "The source table is no longer available; reload from source or create a new table draft";
      return;
    }
  } else {
    insertTableAtCursor(serialized);
    const insertedSourceText = serialized.join("\n");
    const updatedTables = parseMarkdownTables(active.value.text);
    let insertedTableIndex = -1;
    for (let index = updatedTables.length - 1; index >= 0; index -= 1) {
      if (tableSourceText(active.value.text, updatedTables[index]) === insertedSourceText) {
        insertedTableIndex = index;
        break;
      }
    }
    selectedTableIndex.value = insertedTableIndex >= 0 ? insertedTableIndex : Math.max(0, updatedTables.length - 1);
    const insertedTable = updatedTables[selectedTableIndex.value];
    if (insertedTable) {
      tableSourceSnapshot.value = createTableSourceSnapshot(active.value.text, active.value.id, selectedTableIndex.value, insertedTable, normalizedDraft);
    }
    void nextTick().then(() => {
      loadSelectedTable({ force: true });
    });
  }
  isNewTableDraft.value = false;
  tableDraft.value = normalizedDraft;
  refreshTableSourceEditFromDraft();
}

function cancelTableDraft() {
  if (isNewTableDraft.value) {
    tableDraft.value = null;
    isNewTableDraft.value = false;
    refreshTableSourceEditFromDraft();
    if (selectedTable.value) loadSelectedTable({ force: true });
    store.statusMessage = "Cancelled new table";
    return;
  }
  loadSelectedTable({ force: true });
  store.statusMessage = "Discarded table draft changes";
}

function insertTableAtCursor(lines: string[]) {
  const text = editorView?.state.doc.toString() ?? active.value.text;
  const position = editorView?.state.selection.main.to ?? text.length;
  const before = text.slice(0, position);
  const after = text.slice(position);
  const block = lines.join("\n");
  const prefix = !before ? "" : before.endsWith("\n\n") ? "" : before.endsWith("\n") ? "\n" : "\n\n";
  const suffix = !after ? "\n" : after.startsWith("\n") ? "\n" : "\n\n";
  previewTextCommit.cancel();
  store.updateText(`${before}${prefix}${block}${suffix}${after}`);
  void nextTick(() => syncEditorViewFromActiveDocument());
}

function addTableRow() {
  if (!tableDraft.value) return;
  addTableDraftRow(tableDraft.value);
}

function removeTableRow(rowIndex: number) {
  if (!tableDraft.value) return;
  removeTableDraftRow(tableDraft.value, rowIndex);
}

function duplicateTableRow(rowIndex: number) {
  const draft = tableDraft.value;
  if (!draft) return;
  duplicateTableDraftRow(draft, rowIndex);
}

function moveTableRow(rowIndex: number, direction: -1 | 1) {
  const draft = tableDraft.value;
  if (!draft) return;
  moveTableDraftRow(draft, rowIndex, direction);
}

function addTableColumn() {
  if (!tableDraft.value) return;
  addTableDraftColumn(tableDraft.value);
}

function removeTableColumn(columnIndex: number) {
  if (!tableDraft.value) return;
  removeTableDraftColumn(tableDraft.value, columnIndex);
}

function duplicateTableColumn(columnIndex: number) {
  const draft = tableDraft.value;
  if (!draft) return;
  duplicateTableDraftColumn(draft, columnIndex);
}

function moveTableColumn(columnIndex: number, direction: -1 | 1) {
  const draft = tableDraft.value;
  if (!draft) return;
  moveTableDraftColumn(draft, columnIndex, direction);
}

function addTableTotalsRow() {
  addTableFormulaRow("SUM", "Total");
}

function addTableFormulaRow(formula: TableFormulaFunction, label: string = formula) {
  const draft = tableDraft.value;
  if (!draft) return;
  appendTableSummaryFormulaRow(draft, formula, label);
}

function appendCustomTableFormulaRow() {
  const draft = tableDraft.value;
  const row = buildCustomTableFormulaRow();
  if (!draft || !row) return;
  draft.rows.push(row);
}

function applyTableCellSpan() {
  const draft = tableDraft.value;
  if (!draft) return;
  applyTableCellSpanToDraft(draft, {
    rowIndex: tableSpanRow.value,
    columnIndex: tableSpanColumn.value,
    colspan: tableSpanColspan.value,
    rowspan: tableSpanRowspan.value,
  });
}

function clearTableCellSpan() {
  const draft = tableDraft.value;
  if (!draft) return;
  const span = clearTableCellSpanFromDraft(draft, tableSpanRow.value, tableSpanColumn.value);
  if (!span) return;
  tableSpanColspan.value = 1;
  tableSpanRowspan.value = 1;
}

function syncTableSpanControlsFromCell() {
  const draft = tableDraft.value;
  const row = draft?.rows[tableSpanRow.value];
  const value = row?.[tableSpanColumn.value];
  if (value === undefined) {
    tableSpanColspan.value = 1;
    tableSpanRowspan.value = 1;
    return;
  }
  const span = parseTableCellSpan(value);
  tableSpanColspan.value = span.colspan;
  tableSpanRowspan.value = span.rowspan;
}

function buildCustomTableFormulaRow() {
  const draft = tableDraft.value;
  if (!draft) return null;
  return buildTableFormulaRow(draft, {
    formula: tableFormulaFunction.value,
    targetColumn: Number(tableFormulaTargetColumn.value),
    startRow: tableFormulaStartRow.value,
    endRow: tableFormulaEndRow.value,
    label: tableFormulaLabel.value,
  });
}

function clampInteger(value: number, min: number, max: number) {
  if (!Number.isFinite(value)) return min;
  return Math.min(Math.max(Math.trunc(value), min), max);
}

function replaceTableFromPaste() {
  const current = tableDraft.value;
  const nextDraft = tableDraftFromPasteText(tablePasteText.value, {
    fallbackId: current?.id,
    fallbackCaption: current?.caption,
  });
  if (!nextDraft) return;
  tableDraft.value = nextDraft;
  refreshTableSourceEditFromDraft();
}

async function importTableFromSpreadsheet() {
  const selected = await open({
    multiple: false,
    filters: [{ name: "Spreadsheet tables", extensions: ["csv", "tsv", "xlsx"] }],
  });
  if (typeof selected !== "string") return;
  await importSpreadsheetTableFromPath(selected);
}

async function importSelectedSpreadsheetWorksheet() {
  if (!tableImportSourcePath.value) return;
  await importSpreadsheetTableFromPath(tableImportSourcePath.value, tableImportSelectedSheetIndex.value);
}

async function importSpreadsheetTableFromPath(path: string, sheetIndex?: number, sheetName?: string) {
  tableDataBusy.value = true;
  try {
    const response = await invoke<ImportSpreadsheetTableResponse>("import_spreadsheet_table", {
      request: { path, sheet_index: sheetIndex, sheet_name: sheetName },
    });
    applyImportedSpreadsheetTable(response);
    store.sidebar = "tables";
    const sheetSuffix = response.source_format === "xlsx" ? ` worksheet "${response.sheet_name}"` : "";
    store.statusMessage = `Imported ${response.rows} rows and ${response.columns} columns from ${response.source_format.toUpperCase()}${sheetSuffix}`;
    if (response.warnings.length) store.lastError = response.warnings.join(" ");
  } catch (error) {
    store.lastError = error instanceof Error ? error.message : String(error);
    store.statusMessage = "Table import failed";
  } finally {
    tableDataBusy.value = false;
  }
}

function applyImportedSpreadsheetTable(response: ImportSpreadsheetTableResponse) {
  const importedDraft = tableDraftFromPasteText(response.markdown, {
    caption: response.sheet_name || response.source_format.toUpperCase(),
  });
  if (!importedDraft) throw new Error("The selected spreadsheet did not contain a usable table.");
  tableDraft.value = importedDraft;
  tableSourceSnapshot.value = null;
  isNewTableDraft.value = true;
  tablePasteText.value = response.markdown;
  tableImportSourcePath.value = response.source_path;
  tableImportSheetNames.value = response.sheet_names || [];
  tableImportSelectedSheetIndex.value = response.selected_sheet_index || 0;
  refreshTableSourceEditFromDraft();
}

async function exportSelectedTable(format: "csv" | "xlsx") {
  const exportMarkdown = tableMarkdownForExport({
    draftMarkdown: tableDraftMarkdownPreview.value,
    documentText: active.value.text,
    sourceEditDirty: tableSourceEditDirty.value,
    sourceEditText: tableSourceEditText.value,
  });
  if (!exportMarkdown.sourceEditValid) {
    tableSourceEditError.value = "Enter a valid Markdown pipe table before exporting this edited source text.";
    store.statusMessage = "Markdown table source could not be parsed for export";
    return;
  }
  if (!exportMarkdown.markdown.trim()) {
    store.statusMessage = "No table is available to export";
    return;
  }
  const extension = format;
  const outputPath = await save({
    filters: [{ name: format.toUpperCase(), extensions: [extension] }],
    defaultPath: `${active.value.title.replace(/\.[^.]+$/, "")}-table.${extension}`,
  });
  if (!outputPath) return;
  tableDataBusy.value = true;
  try {
    const response = await invoke<ExportMarkdownTablesResponse>("export_markdown_tables", {
      request: {
        markdown: exportMarkdown.markdown,
        output_path: outputPath,
        format,
        table_index: 0,
      },
    });
    const sourceLabel = exportMarkdown.source === "source-edit" ? " from edited Markdown source" : "";
    await waitForPreviewCompileIdle();
    store.statusMessage = `Exported ${response.exported_tables} table${response.exported_tables === 1 ? "" : "s"}${sourceLabel} to ${format.toUpperCase()}`;
  } catch (error) {
    store.lastError = error instanceof Error ? error.message : String(error);
    store.statusMessage = `${format.toUpperCase()} table export failed`;
  } finally {
    tableDataBusy.value = false;
  }
}

async function waitForPreviewCompileIdle(timeoutMs = 1200) {
  const startedAt = performance.now();
  while (store.compileBusy && performance.now() - startedAt < timeoutMs) {
    await new Promise((resolve) => window.setTimeout(resolve, 25));
  }
}

function insertSqlTransformTemplate() {
  insertBlock([
    '```sql database="data/example.sqlite"',
    "SELECT",
    "  name,",
    "  amount",
    "FROM results",
    "ORDER BY amount DESC",
