}

.app-shell[data-high-contrast="true"] .toolbar-visibility-menu {
  border-color: #000000;
}

.app-shell[data-high-contrast="true"] .toolbar-visibility-trigger small {
  background: #000000;
  color: #ffffff;
}

.app-shell[data-high-contrast="true"] .floating-toolbar-restore,
.app-shell[data-high-contrast="true"] .workspace-writing-restore,
.app-shell[data-high-contrast="true"] .workspace-toolbar-restore {
  border-color: #000000;
  background: #ffffff;
  color: #000000;
}

.app-shell[data-high-contrast="true"] :focus-visible,
.app-shell[data-high-contrast="true"] .skip-links a:focus {
  outline: 3px solid #000000;
  outline-offset: 2px;
}

.app-shell[data-reduced-motion="true"] * {
  scroll-behavior: auto;
  transition-duration: 0s;
  animation-duration: 0s;
  animation-iteration-count: 1;
}

@media (prefers-reduced-motion: reduce) {
  .app-shell * {
    scroll-behavior: auto;
    transition-duration: 0s;
    animation-duration: 0s;
    animation-iteration-count: 1;
  }
}

.skip-links {
  position: fixed;
  top: 8px;
  left: 8px;
  z-index: 1000;
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  pointer-events: none;
}

.skip-links a {
  position: absolute;
  top: -999px;
  left: 0;
  border: 2px solid #18212f;
  border-radius: 6px;
  padding: 6px 10px;
  background: #ffffff;
  color: #18212f;
  font-weight: 700;
  text-decoration: none;
  pointer-events: auto;
}

.skip-links a:focus {
  position: static;
  transform: none;
  outline: 3px solid #f6c343;
  outline-offset: 2px;
}

.titlebar,
.command-bar,
.status-bar {
  display: flex;
  align-items: center;
  gap: 8px;
  min-width: 0;
  padding: 0 10px;
  border-bottom: 1px solid #c9d2dc;
  background: #f7f9fb;
}

.app-menu-bar {
  display: inline-flex;
  align-items: stretch;
  flex: 0 0 auto;
  gap: 1px;
  min-width: 0;
  height: 30px;
  padding-right: 6px;
  border-right: 1px solid #d7dee7;
}

.app-menu {
  position: relative;
  display: inline-flex;
  align-items: stretch;
}

.app-menu-trigger {
  min-width: 0;
  min-height: 28px;
  padding: 0 8px;
  border-color: transparent;
  background: transparent;
  color: #26364a;
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0;
}

.app-menu-trigger:hover,
.app-menu-trigger:focus-visible,
.app-menu-trigger[aria-expanded="true"] {
  border-color: #c5d0dc;
  background: #eef5ff;
}

.toolbar-visibility-menu {
  margin-left: 4px;
  padding-left: 6px;
  border-left: 1px solid #d7dee7;
}

.toolbar-visibility-trigger {
  display: inline-grid;
  grid-template-columns: 13px auto auto;
  align-items: center;
  gap: 5px;
  border-color: #8aa5c2;
  background: #edf6ff;
  color: #173e63;
}

.toolbar-visibility-trigger svg {
  width: 13px;
  height: 13px;
  fill: none;
  stroke: currentColor;
  stroke-linecap: round;
  stroke-linejoin: round;
  stroke-width: 2;
}

.toolbar-visibility-trigger small {
  min-width: 16px;
  padding: 1px 5px;
  border-radius: 999px;
  background: #315f8d;
  color: #ffffff;
  font-size: 10px;
  font-weight: 850;
  line-height: 1.2;
}

.toolbar-visibility-panel {
  min-width: 300px;
}

.app-menu-panel {
  position: absolute;
  top: calc(100% + 4px);
  left: 0;
  z-index: 40;
  display: grid;
  gap: 6px;
  width: max-content;
  min-width: 270px;
  max-width: min(420px, 88vw);
  max-height: min(72vh, 720px);
  overflow: auto;
  padding: 8px;
  border: 1px solid #b8c5d4;
  border-radius: 8px;
  background: #ffffff;
  box-shadow: 0 16px 36px rgba(23, 37, 54, 0.18);
}

.app-menu-group {
  display: grid;
  gap: 2px;
  padding: 0 0 6px;
  border-bottom: 1px solid #e2e8f0;
}

.app-menu-group:last-child {
  padding-bottom: 0;
  border-bottom: 0;
}

.app-menu-group-label {
  padding: 3px 7px;
  color: #65758a;
  font-size: 10px;
  font-weight: 800;
  letter-spacing: 0;
  line-height: 1.1;
  text-transform: uppercase;
}

.app-menu-group button {
  display: grid;
  justify-items: start;
  gap: 2px;
  min-height: 30px;
  padding: 5px 8px;
  border-color: transparent;
  background: transparent;
  color: #172439;
  font-size: 12px;
  line-height: 1.2;
  text-align: left;
}

.app-menu-group button:hover,
.app-menu-group button:focus-visible {
  border-color: #c9d8e8;
  background: #eef5ff;
}

.app-menu-group button small {
  max-width: 360px;
  color: #65758a;
  font-size: 11px;
  font-weight: 500;
}

.document-tabs {
  display: flex;
  min-width: 0;
  flex: 1;
  gap: 8px;
  overflow-x: auto;
}

.tab-group {
  display: flex;
  align-items: center;
  flex: 0 0 auto;
  gap: 6px;
  min-width: 0;
  padding-right: 8px;
  border-right: 1px solid #d7dee7;
}

.tab-group:last-child {
  border-right: 0;
  padding-right: 0;
}

.tab-group-header {
  display: flex;
  align-items: center;
  gap: 5px;
  min-width: 76px;
  max-width: 140px;
  min-height: 28px;
  padding: 2px 4px 2px 6px;
  border: 1px solid #d7dee7;
  border-radius: 6px;
  background: #ffffff;
  color: #526171;
  font-size: 11px;
  line-height: 1.2;
  text-transform: uppercase;
}

.tab-group-title {
  display: grid;
  min-width: 0;
  flex: 1;
  gap: 1px;
}

.tab-group-title span {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.tab-group-title small {
  color: #7b8794;
  font-size: 10px;
}

.tab {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  max-width: 280px;
  min-height: 30px;
  padding: 0 3px 0 0;
  border: 1px solid #bac4d1;
  border-radius: 6px;
  background: #f3f6fa;
}

.tab[draggable="true"] {
  cursor: grab;
}

.tab.active {
  border-color: #275da8;
  background: #ffffff;
  box-shadow: inset 0 -2px 0 #275da8;
}

.tab-drag-handle {
  display: inline-flex;
  align-items: center;
  align-self: stretch;
  padding: 0 2px 0 5px;
  color: #7b8794;
  cursor: grab;
  font-size: 11px;
  line-height: 1;
  letter-spacing: 0;
}

.tab-main {
  display: grid;
  grid-template-columns: auto minmax(0, 1fr);
  align-items: center;
  column-gap: 6px;
  min-width: 0;
  flex: 1;
  min-height: 28px;
  padding: 4px 8px;
  border: 0;
  background: transparent;
  text-align: left;
}

.tab-main .tab-title,
.tab-main .tab-file-name {
  display: block;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.tab-main .tab-title {
  grid-column: 2;
  line-height: 1.05;
}

.tab-main .tab-file-name {
  grid-column: 2;
  color: #607083;
  font-size: 10px;
  line-height: 1.05;
}

.tab-dirty {
  grid-column: 1;
  grid-row: 1 / span 2;
  width: 6px;
  height: 6px;
  flex: 0 0 6px;
  border-radius: 50%;
  background: #c68a1a;
}

.tab-icon-button {
  width: 24px;
  min-width: 24px;
  height: 24px;
  min-height: 24px;
  padding: 0;
  border-color: transparent;
  background: transparent;
  color: #607083;
}

.tab-icon-button:hover,
.tab-icon-button.active {
  border-color: #c5cfdb;
  background: #eef4fb;
  color: #174a88;
}

.tab-icon-button:disabled {
  opacity: 0.35;
  cursor: default;
}

.window-meta,
.status-bar {
  color: #526171;
  font-size: 12px;
}

.window-meta {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  min-width: 0;
  overflow: hidden;
  white-space: nowrap;
}

.titlebar-toolbar-tray {
  flex: 1 1 auto;
  max-width: min(64vw, 860px);
}

.release-badge {
  display: inline-flex;
  align-items: center;
  min-height: 22px;
  padding: 0 8px;
  border: 1px solid #9fb0c2;
  border-radius: 6px;
  background: #ffffff;
  color: #253142;
  font-weight: 700;
  line-height: 1;
  text-transform: uppercase;
}

.release-draft {
  border-color: #c68a1a;
  background: #fff7df;
  color: #714b00;
}

.release-in-review {
  border-color: #4575b4;
  background: #e8f1ff;
  color: #164071;
}

.release-approved {
  border-color: #2f855a;
  background: #e7f7ed;
  color: #19543a;
}

.release-published {
  border-color: #5d55a5;
  background: #f0edff;
  color: #3b3474;
}

.release-archived {
  border-color: #7b8794;
  background: #eef1f4;
  color: #3d4852;
}

.command-bar {
  display: grid;
  align-items: stretch;
  gap: 4px;
  min-height: 0;
  overflow: visible;
  padding: 6px 8px;
  border-bottom-color: #b9c6d4;
  background: #f7f9fc;
}

.app-shell.toolbars-collapsed .command-bar {
  height: 0;
  min-height: 0;
  padding-block: 0;
  border-bottom-width: 0;
  overflow: hidden;
}

.command-toolbar-row {
  display: flex;
  align-items: center;
  gap: 6px;
  min-width: 0;
  padding: 2px 0;
}

.command-toolbar-heading {
  display: inline-flex;
  align-items: center;
  justify-content: flex-start;
  gap: 5px;
  width: 92px;
  flex: 0 0 92px;
  min-height: 28px;
  padding: 0 6px;
  border: 1px solid transparent;
  background: transparent;
  color: #5b6c80;
  font-size: 10px;
  font-weight: 800;
  letter-spacing: 0;
  line-height: 1;
  text-align: left;
  text-transform: uppercase;
}

.command-toolbar-heading:hover,
.command-toolbar-heading:focus-visible {
  border-color: #c7d2df;
  background: #ffffff;
}

.command-toolbar-heading svg {
  width: 13px;
  height: 13px;
  flex: 0 0 13px;
  fill: none;
  stroke: currentColor;
  stroke-linecap: round;
  stroke-linejoin: round;
  stroke-width: 2;
}

.command-toolbar-heading span {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
}

.command-toolbar-row-view {
  align-items: center;
}

.collapsed-toolbar-tray {
  display: flex;
  align-items: center;
  gap: 5px;
  min-width: 0;
  min-height: 26px;
  padding: 2px 4px;
  border: 1px solid #8aa5c2;
  border-radius: 7px;
  background: #edf6ff;
  box-shadow: 0 0 0 1px rgba(49, 95, 141, 0.08), inset 0 1px 0 rgba(255, 255, 255, 0.82);
  overflow-x: auto;
}

.collapsed-toolbar-tray-label {
  display: inline-flex;
  flex: 0 0 auto;
  flex-direction: column;
  gap: 2px;
  min-width: 118px;
  color: #173e63;
  font-size: 10px;
  font-weight: 800;
  letter-spacing: 0;
  line-height: 1;
  text-transform: uppercase;
}

.collapsed-toolbar-tray-label small {
  color: #4c647f;
  font-size: 10px;
  font-weight: 650;
  line-height: 1.1;
  text-transform: none;
}

.collapsed-toolbar-pill {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  flex: 0 0 auto;
  min-height: 24px;
  padding: 0 8px;
  border: 1px solid #cbd7e5;
  border-radius: 6px;
  background: #ffffff;
  color: #445367;
  font-size: 10px;
  font-weight: 750;
  letter-spacing: 0;
  line-height: 1;
}

.collapsed-toolbar-pill:hover,
.collapsed-toolbar-pill:focus-visible {
  border-color: #9db2ca;
  background: #eef5ff;
}

.collapsed-toolbar-pill-primary {
  border-color: #315f8d;
  background: #e7f1fb;
  color: #173e63;
  font-weight: 800;
}

.collapsed-toolbar-pill svg {
  width: 12px;
  height: 12px;
  flex: 0 0 12px;
  fill: none;
  stroke: currentColor;
  stroke-linecap: round;
  stroke-linejoin: round;
  stroke-width: 2;
}

.floating-toolbar-restore {
  position: fixed;
  top: 44px;
  right: 12px;
  z-index: 60;
  display: grid;
  grid-template-columns: 16px auto;
  grid-template-rows: auto auto;
  align-items: center;
  column-gap: 6px;
  row-gap: 1px;
  min-height: 34px;
  padding: 4px 10px;
  border: 1px solid #315f8d;
  border-radius: 7px;
  background: #f7fbff;
  color: #173e63;
  box-shadow: 0 10px 24px rgba(24, 36, 52, 0.18), 0 0 0 1px rgba(255, 255, 255, 0.75);
  font-size: 11px;
  font-weight: 850;
  line-height: 1;
  text-align: left;
}

.floating-toolbar-restore:hover,
.floating-toolbar-restore:focus-visible {
  border-color: #174a79;
  background: #e9f4ff;
  box-shadow: 0 12px 28px rgba(24, 36, 52, 0.24), 0 0 0 3px rgba(99, 134, 180, 0.22);
}

.floating-toolbar-restore svg {
  grid-row: 1 / span 2;
  width: 15px;
  height: 15px;
  fill: none;
  stroke: currentColor;
  stroke-linecap: round;
  stroke-linejoin: round;
  stroke-width: 2;
}

.floating-toolbar-restore small {
  color: #4c647f;
  font-size: 9px;
  font-weight: 750;
  line-height: 1.05;
}

.app-shell.writing-space-maximized .floating-toolbar-restore {
  display: none;
}

.workspace-toolbar-restore {
  position: absolute;
  top: 8px;
  right: 12px;
  z-index: 35;
  display: inline-grid;
  grid-template-columns: 15px auto;
  grid-template-rows: auto auto;
  align-items: center;
  column-gap: 6px;
  row-gap: 1px;
  min-height: 32px;
  padding: 4px 9px;
  border: 1px solid #315f8d;
  border-radius: 7px;
  background: #f7fbff;
  color: #173e63;
  box-shadow: 0 8px 18px rgba(24, 36, 52, 0.18), 0 0 0 1px rgba(255, 255, 255, 0.72);
  font-size: 10px;
  font-weight: 850;
  line-height: 1;
  text-align: left;
}

.workspace-toolbar-restore-offset {
  top: 52px;
}

.workspace-writing-restore {
  position: absolute;
  top: 8px;
  right: 12px;
  z-index: 42;
  display: inline-grid;
  grid-template-columns: 16px auto;
  grid-template-rows: auto auto;
  align-items: center;
  column-gap: 7px;
  row-gap: 1px;
  min-height: 36px;
  max-width: min(320px, calc(100vw - 24px));
  padding: 5px 11px;
  border: 1px solid #214f7c;
  border-radius: 7px;
  background: #f2f8ff;
  color: #113a61;
  box-shadow: 0 10px 24px rgba(24, 36, 52, 0.22), 0 0 0 1px rgba(255, 255, 255, 0.78);
  font-size: 11px;
  font-weight: 875;
  line-height: 1;
  text-align: left;
}

.workspace-toolbar-restore:hover,
.workspace-toolbar-restore:focus-visible,
.workspace-writing-restore:hover,
.workspace-writing-restore:focus-visible {
  border-color: #174a79;
  background: #e9f4ff;
  box-shadow: 0 10px 22px rgba(24, 36, 52, 0.23), 0 0 0 3px rgba(99, 134, 180, 0.2);
}

.workspace-toolbar-restore svg,
.workspace-writing-restore svg {
  grid-row: 1 / span 2;
  width: 14px;
  height: 14px;
  fill: none;
  stroke: currentColor;
  stroke-linecap: round;
  stroke-linejoin: round;
  stroke-width: 2;
}

.workspace-writing-restore svg {
  width: 15px;
  height: 15px;
}

.workspace-toolbar-restore small,
.workspace-writing-restore small {
  color: #4c647f;
  font-size: 9px;
  font-weight: 750;
  line-height: 1.05;
}

.command-group {
  display: inline-flex;
  align-items: center;
  flex: 0 0 auto;
  gap: 5px;
  min-height: 34px;
  padding: 3px 5px;
  border: 1px solid #d9e1ea;
  border-radius: 6px;
  background: #ffffff;
}

.command-group:first-child {
  padding-left: 7px;
}

.command-group:last-child {
  padding-right: 7px;
}

.command-group-label {
  min-width: auto;
  color: #607083;
  font-size: 9px;
  font-weight: 700;
  letter-spacing: 0;
  line-height: 1.1;
  text-transform: uppercase;
}

.command-group-actions {
  display: inline-flex;
  align-items: center;
  gap: 4px;
}

.icon-command {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  min-width: 34px;
  height: 28px;
  padding: 0 6px;
  border-color: #c5d0dc;
  background: #f8fafc;
  color: #203044;
  font-size: var(--toolbar-font-size, 10px);
  line-height: 1.1;
  white-space: nowrap;
}

.compact-toolbar-toggle {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  min-height: 28px;
  padding: 0 7px;
  border-color: #c5d0dc;
  background: #f8fafc;
  color: #203044;
  font-size: var(--toolbar-font-size, 10px);
  font-weight: 700;
  line-height: 1.1;
  white-space: nowrap;
}

.icon-command.primary {
  border-color: #7fa2cd;
  background: #eaf3ff;
  color: #143f70;
}

.icon-command:disabled {
  cursor: not-allowed;
  opacity: 0.55;
}

.command-icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
  flex: 0 0 16px;
}

.command-icon svg {
  width: 16px;
  height: 16px;
  fill: none;
  stroke: currentColor;
  stroke-linecap: round;
  stroke-linejoin: round;
  stroke-width: 1.9;
}

.command-label {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
}

.app-shell[data-toolbar-display="icons"] .icon-command {
  width: 36px;
  padding: 0;
}

.app-shell[data-toolbar-display="icons"] .command-label,
.app-shell[data-toolbar-display="text"] .command-icon {
  display: none;
}

.app-shell[data-toolbar-display="text"] .icon-command {
  min-width: auto;
}

.command-group-view {
  grid-template-columns: auto repeat(3, minmax(104px, max-content));
}

.compact-field {
  display: inline-grid;
  flex: 0 0 auto;
  grid-template-columns: auto minmax(84px, max-content);
  align-items: center;
  gap: 5px;
  color: #526171;
  font-size: var(--toolbar-font-size, 10px);
  font-weight: 700;
}

.compact-field span {
  text-transform: uppercase;
}

.compact-field select {
  height: 28px;
  min-width: 96px;
  font-size: var(--toolbar-font-size, 10px);
}

.compact-field input[type="range"] {
  width: 92px;
}

.compact-field output {
  min-width: 32px;
  color: #526171;
  font-variant-numeric: tabular-nums;
}

.compact-field-range {
  grid-template-columns: auto 92px 32px;
}

.trust-prompt {
  display: flex;
  align-items: stretch;
  gap: 8px;
  overflow-x: auto;
  padding: 8px 10px;
  border-bottom: 1px solid #d8b66d;
  background: #fff8e8;
}

.trust-prompt-item {
  display: grid;
  grid-template-columns: minmax(220px, 1fr) auto;
  align-items: center;
  min-width: min(100%, 560px);
  gap: 12px;
  padding: 8px;
  border: 1px solid #d8b66d;
  border-radius: 6px;
  background: #ffffff;
}

.trust-prompt-item strong,
.trust-prompt-item span,
.trust-prompt-item small {
  display: block;
}

.trust-prompt-item span {
  overflow-wrap: anywhere;
  color: #374151;
  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", monospace;
  font-size: 12px;
}

.trust-prompt-item small {
  color: #526171;
}

.trust-prompt-actions {
  display: inline-flex;
  gap: 6px;
}

.divider {
  width: 1px;
  height: 22px;
  background: #c9d2dc;
}

.workspace {
  position: relative;
  display: grid;
  grid-template-columns:
    260px minmax(260px, calc((100vw - 268px) * var(--editor-ratio, 0.5))) 8px
    minmax(260px, 1fr);
  min-height: 0;
}

.workspace.mode-source,
.workspace.mode-focus {
  grid-template-columns: 260px minmax(0, 1fr);
}

.workspace.mode-preview,
.workspace.mode-export,
.workspace.mode-presentation {
  grid-template-columns: 260px minmax(0, 1fr);
}

.workspace.mode-outline {
  grid-template-columns: minmax(0, 1fr);
}

.workspace.workspace-writing-maximized {
  grid-template-columns: minmax(0, 1fr);
}

.sidebar,
.editor-pane,
.preview-pane,
.outline-mode-pane {
  min-height: 0;
  overflow: auto;
  border-right: 1px solid #c9d2dc;
}

.outline-mode-pane {
  display: grid;
  grid-template-rows: auto minmax(0, 1fr);
  gap: 12px;
  padding: 16px;
  background: #f7f9fc;
}

.outline-mode-header {
  display: flex;
  align-items: start;
  justify-content: space-between;
  gap: 16px;
  padding-bottom: 12px;
  border-bottom: 1px solid #d8e1eb;
}

.outline-mode-header h2 {
  margin: 0 0 4px;
  font-size: 20px;
}

.outline-mode-header p {
  margin: 0;
  color: #526171;
}

.outline-mode-create {
  display: flex;
  align-items: end;
  flex-wrap: wrap;
  gap: 8px;
}

.outline-mode-create label {
  display: grid;
  gap: 4px;
  color: #526171;
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
}

.outline-mode-create input {
  min-width: 220px;
}

.outline-mode-list {
  display: grid;
  align-content: start;
  gap: 8px;
  overflow: auto;
}

.outline-mode-row {
  display: grid;
  grid-template-columns: 112px minmax(180px, 1fr) 150px auto;
  align-items: center;
  gap: 8px;
  margin-left: calc(var(--outline-depth, 0) * 22px);
  padding: 8px;
  border: 1px solid #d9e1ea;
  border-radius: 6px;
  background: #ffffff;
}

.outline-mode-kind {
  color: #5b6c80;
  font-size: 11px;
  font-weight: 800;
  letter-spacing: 0;
  text-transform: uppercase;
}

.outline-mode-row input,
.outline-mode-row select {
  width: 100%;
}

.outline-mode-actions {
  display: inline-flex;
  justify-content: flex-end;
  gap: 6px;
  white-space: nowrap;
}

.outline-mode-empty {
  display: grid;
  place-content: center;
  gap: 8px;
  min-height: 280px;
  text-align: center;
}

.outline-mode-empty h3,
.outline-mode-empty p {
  margin: 0;
}

.pane-splitter {
  width: 8px;
  min-width: 8px;
  padding: 0;
  border: 0;
  border-right: 1px solid #c9d2dc;
  border-left: 1px solid #d7dee7;
  background: #e4eaf1;
  cursor: col-resize;
}

.pane-splitter:hover,
.pane-splitter:focus-visible {
  background: #2f6f9f;
  outline: none;
}

.sidebar {
  padding: 12px;
  background: #f7f9fb;
}

.sidebar h2 {
  margin: 0 0 12px;
  font-size: 13px;
  text-transform: uppercase;
  color: #526171;
}

.sidebar h3 {
  margin: 16px 0 8px;
  font-size: 13px;
}

.sidebar label {
  display: grid;
  gap: 6px;
  margin-bottom: 12px;
}

.outline-planner {
  display: grid;
  gap: 8px;
  margin-bottom: 12px;
  padding-bottom: 12px;
  border-bottom: 1px solid #d7dee7;
}

.outline-planner textarea {
  resize: vertical;
  min-height: 136px;
  font-family: var(--editor-font, "SFMono-Regular", Consolas, monospace);
}

.cover-builder {
  display: grid;
  gap: 10px;
  margin-bottom: 12px;
  padding: 10px;
  border: 1px solid #d7dee7;
  border-left: 3px solid #2f6f7e;
  border-radius: 6px;
  background: #ffffff;
}

.cover-builder header,
.cover-builder-actions {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 8px;
}

.cover-builder h3 {
  margin: 0;
  font-size: 13px;
}

.cover-builder header small {
  color: #526171;
  font-size: 11px;
  overflow-wrap: anywhere;
}

.cover-builder-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 8px;
}

.cover-builder-actions {
  flex-wrap: wrap;
  justify-content: flex-start;
}

.outline-planner-actions {
  display: grid;
  grid-template-columns: 1fr;
  gap: 6px;
}

.outline-library {
  display: grid;
  gap: 8px;
  margin-bottom: 12px;
  padding-bottom: 12px;
  border-bottom: 1px solid #d7dee7;
}

.document-map {
  display: grid;
  gap: 8px;
  margin-bottom: 12px;
  padding-bottom: 12px;
  border-bottom: 1px solid #d7dee7;
}

.document-map header,
.document-map-counts {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.document-map h3 {
  margin: 0;
  font-size: 13px;
}

.document-map header small {
  color: #526171;
  font-size: 11px;
}

.document-map-controls {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: 8px;
}

.document-map-counts {
  flex-wrap: wrap;
  justify-content: flex-start;
}

.document-map-counts button {
  display: inline-grid;
  grid-template-columns: auto auto;
  gap: 4px;
  align-items: center;
  min-height: 28px;
  padding: 4px 7px;
}

.document-map-counts button.active,
.document-map header button.active {
  border-color: #2f6f9f;
  background: #eaf4fb;
}

.document-map-list {
  display: grid;
  gap: 6px;
  max-height: 320px;
  overflow: auto;
}

.document-map-row {
  display: grid;
  grid-template-columns: auto minmax(0, 1fr) auto;
  gap: 4px 7px;
  align-items: center;
  width: 100%;
  padding: 7px;
  border: 1px solid #d7dee7;
  border-left: 3px solid #8897a7;
  border-radius: 6px;
  background: #ffffff;
  color: inherit;
  text-align: left;
}

.document-map-row[data-kind="comment"],
.document-map-row[data-kind="citation"],
.document-map-row[data-kind="diagnostic"] {
  border-left-color: #a45b39;
}

.document-map-row[data-kind="figure"],
.document-map-row[data-kind="table"],
.document-map-row[data-kind="equation"] {
  border-left-color: #2f6f7e;
}

.document-map-kind,
.document-map-status {
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
}

.document-map-label,
.document-map-row small {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.document-map-row small {
  grid-column: 2 / 4;
  color: #526171;
  font-size: 11px;
}

.outline-library header,
.outline-template-card header,
.outline-template-actions,
.outline-library-actions {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.outline-library h3 {
  margin: 0;
  font-size: 13px;
}

.outline-library-filters {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: 8px;
}

.outline-template-list {
  display: grid;
  gap: 8px;
  max-height: 420px;
  overflow: auto;
}

.outline-template-card {
  display: grid;
  gap: 6px;
  padding: 8px;
  border: 1px solid #d7dee7;
  border-radius: 6px;
  background: #ffffff;
}

.outline-template-card p {
  margin: 0;
  color: #526171;
}

.outline-template-card pre {
  max-height: 140px;
  margin: 0;
  overflow: auto;
  white-space: pre-wrap;
  font-size: 11px;
}

.outline-template-actions {
  justify-content: flex-start;
  flex-wrap: wrap;
}

.outline-row {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  align-items: baseline;
  gap: 8px;
  width: 100%;
  margin-bottom: 2px;
  border: 0;
  background: transparent;
  text-align: left;
}

.outline-row span {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
}

.outline-row small {
  color: #526171;
  font-size: 11px;
}

.file-row {
  display: grid;
  grid-template-columns: 18px minmax(0, 1fr);
  width: 100%;
  margin: 1px 0;
  border: 0;
  background: transparent;
  text-align: left;
}

.file-row span:last-child,
.workspace-root {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.file-row.directory {
  color: #526171;
  font-weight: 600;
}

.file-row.active {
  background: #e5edf7;
  color: #174a88;
}

.document-set-manager {
  display: grid;
  gap: 8px;
  margin: 10px 0 12px;
  padding: 8px;
  border: 1px solid #d9e2ed;
  background: #f8fafc;
}

.document-set-manager header,
.document-set-list article,
.document-set-actions {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.document-set-manager h3,
.document-set-manager p {
  margin: 0;
}

.document-set-manager label {
  display: grid;
  gap: 4px;
  font-size: 12px;
  font-weight: 600;
}

.document-set-list {
  display: grid;
  gap: 6px;
}

.document-set-list article {
  padding: 6px;
  border: 1px solid #d9e2ed;
  background: #ffffff;
}

.document-set-list article div {
  display: grid;
  gap: 2px;
}

.app-shell[data-theme="dark"] .document-set-manager {
  border-color: #34465a;
  background: #1b2736;
}

.app-shell[data-theme="dark"] .document-set-list article {
  border-color: #34465a;
  background: #223246;
}

.app-shell[data-theme="dark"] .include-builder label {
  color: #e6edf5;
}

.app-shell[data-theme="dark"] .include-directive-preview {
  border-color: #34465a;
  background: #162231;
  color: #e6edf5;
}

.sidebar-hint {
  margin: 6px 0 12px;
  color: #526171;
  font-size: 12px;
}

.include-graph {
  display: grid;
  gap: 8px;
}

.include-edge {
  display: grid;
  gap: 6px;
  padding: 8px;
  border-left: 3px solid #2f6f7e;
  background: #ffffff;
}

.include-edge p {
  margin: 0;
  min-width: 0;
  overflow-wrap: anywhere;
}

.include-edge small {
  color: #526171;
}

.include-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.include-builder label {
  display: grid;
  gap: 4px;
  color: #223246;
  font-size: 12px;
  font-weight: 650;
}

.include-directive-preview {
  display: block;
  padding: 7px 8px;
  border: 1px solid #d5dee8;
  border-radius: 6px;
  background: #f6f8fb;
  color: #1b2736;
  overflow-wrap: anywhere;
}

.reference-manager {
  display: grid;
  gap: 8px;
  margin: 6px 0 12px;
}

.data-refresh-workflow {
  display: grid;
  gap: 8px;
  padding: 9px;
  border: 1px solid #d5dee8;
  border-left: 3px solid #2f6f7e;
  background: #f8fafc;
}

.data-refresh-workflow header {
  display: grid;
  gap: 3px;
}

.data-refresh-workflow header span {
  color: #526070;
  font-size: 12px;
}

