.template-filters,
.custom-template-editor,
.template-pack-manager {
  display: grid;
  gap: 8px;
  margin-bottom: 12px;
}

.template-filters {
  grid-template-columns: repeat(auto-fit, minmax(130px, 1fr));
}

.transform-template-assistance {
  display: grid;
  gap: 8px;
  margin: 0 0 12px;
  padding: 10px;
  border: 1px solid #c9d2dc;
  border-left: 3px solid #6a5a2f;
  border-radius: 7px;
  background: #fffdf7;
}

.transform-template-assistance header {
  display: flex;
  align-items: start;
  justify-content: space-between;
  gap: 10px;
}

.template-pack-manager {
  padding: 10px;
  border: 1px solid #c9d2dc;
  border-left: 3px solid #6857a8;
  border-radius: 7px;
  background: #fbfaff;
}

.template-pack-manager header,
.template-pack-fields {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
  gap: 8px;
  align-items: start;
}

.template-pack-manager header div {
  display: grid;
  gap: 2px;
  min-width: 0;
}

.template-pack-manager header span {
  color: #526171;
  font-size: 12px;
  line-height: 1.35;
}

.template-pack-counts {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(120px, 1fr));
  gap: 6px;
}

.template-pack-counts span {
