}

.transform-template-assistance header div {
  display: grid;
  gap: 2px;
}

.transform-template-assistance h3,
.transform-template-assistance p,
.transform-template-assistance ul {
  margin: 0;
}

.transform-template-assistance header span,
.transform-template-assistance p,
.transform-template-assistance small,
.transform-template-assistance label {
  color: #526171;
  font-size: 12px;
  line-height: 1.35;
}

.transform-template-assistance label {
  display: grid;
  gap: 4px;
}

.transform-template-assistance textarea {
  width: 100%;
  min-height: 120px;
  resize: vertical;
  border: 1px solid #bac4d1;
  border-radius: 6px;
  padding: 8px;
  color: #18212f;
  background: #ffffff;
}

.business-template-hub {
  display: grid;
  gap: 8px;
  margin-bottom: 12px;
  padding: 10px;
  border: 1px solid #c9d2dc;
  border-left: 3px solid #566b2f;
  border-radius: 7px;
  background: #fbfcf8;
}

.configuration-setup-card {
  display: grid;
  gap: 10px;
  margin-bottom: 14px;
  padding: 10px;
  border: 1px solid #c9d2dc;
  border-left: 3px solid #2f6f78;
  border-radius: 7px;
  background: #f7fcfc;
}

.configuration-setup-card header,
.configuration-setup-detail header {
  display: flex;
  justify-content: space-between;
  gap: 12px;
  align-items: start;
}

.configuration-setup-card header div,
.configuration-setup-detail header div {
  display: grid;
  gap: 2px;
  min-width: 0;
}

.configuration-setup-card header span,
.configuration-setup-detail header span {
  color: #526171;
  font-size: 12px;
}

.configuration-status-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(130px, 1fr));
  gap: 6px;
}

.configuration-status-chip {
  display: grid;
  gap: 2px;
  min-height: 52px;
  padding: 7px 8px;
  border: 1px solid #d8e0e8;
