}

.configuration-status-chip.ready {
  border-color: #9bbd9c;
  background: #f4fbf4;
}

.configuration-status-chip.needs-work {
  border-color: #d8c28a;
  background: #fffaf0;
}

.configuration-status-chip small {
  color: #526171;
  font-size: 11px;
}

.configuration-setup-assistance {
  display: grid;
  gap: 8px;
  padding: 10px;
  border: 1px solid #d7dee7;
  border-radius: 7px;
  background: #ffffff;
}

.configuration-setup-assistance header {
  display: flex;
  justify-content: space-between;
  gap: 12px;
  align-items: start;
}

.configuration-setup-assistance article,
.configuration-setup-assistance label {
  display: grid;
  gap: 4px;
}

.configuration-setup-assistance p,
.configuration-setup-assistance ul {
  margin: 0;
  font-size: 12px;
  line-height: 1.4;
}

.configuration-setup-assistance small,
.configuration-setup-assistance header span {
  color: #526171;
  font-size: 12px;
}

.business-template-hub header,
.business-profile-preview header {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 8px;
  align-items: start;
}

.business-template-hub header div,
.business-profile-preview header {
  min-width: 0;
}

.business-template-hub header div,
.business-template-hub label,
.business-profile-preview {
  display: grid;
  gap: 4px;
}

.business-template-hub header span,
.business-template-hub .sidebar-hint,
.business-profile-preview header span,
.snippet-card small,
.wizard-step-list span,
