  font-size: 12px;
  line-height: 1.35;
}

.business-template-list,
.snippet-list {
  display: grid;
  gap: 8px;
}

.versioned-clause-editor {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 8px;
  padding: 9px;
  border: 1px solid #d8e0e8;
  border-radius: 7px;
  background: #f9fbfd;
}

.versioned-clause-editor label:nth-of-type(5),
.versioned-clause-editor label:nth-of-type(6),
.versioned-clause-editor .template-actions,
.versioned-clause-editor .sidebar-hint {
  grid-column: 1 / -1;
}

.versioned-clause-editor textarea {
  min-height: 64px;
  resize: vertical;
}

.app-shell[data-theme="dark"] .versioned-clause-editor {
  border-color: #30445d;
  background: #1f2b3b;
}

@media (prefers-color-scheme: dark) {
  .app-shell[data-theme="system"] .versioned-clause-editor {
    border-color: #30445d;
    background: #1f2b3b;
  }
}

.business-document-card details ol {
  margin: 6px 0 0;
  padding-left: 18px;
}

.business-wizard-assistance li {
  display: grid;
  gap: 4px;
  margin-bottom: 8px;
}

.business-wizard-assistance p {
  margin: 0;
  font-size: 12px;
  line-height: 1.35;
}

.business-wizard-assistance small {
  color: #526171;
}

.business-wizard-assistance button {
  justify-self: start;
  min-height: 28px;
  padding: 4px 8px;
  font-size: 12px;
}

.rfp-source-grid {
  display: grid;
  grid-template-columns: minmax(0, 0.8fr) minmax(0, 1.2fr);
  gap: 8px;
}

.rfp-analysis-panel {
  display: grid;
  gap: 8px;
  padding-top: 8px;
  border-top: 1px solid #d8e0e8;
}

.rfp-analysis-metrics {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 6px;
}

.rfp-analysis-metrics span {
  padding: 6px 8px;
  border: 1px solid #d8e0e8;
  border-radius: 6px;
  background: #ffffff;
  font-size: 12px;
}

.rfp-analysis-panel details {
  padding: 6px 8px;
  border: 1px solid #d8e0e8;
  border-radius: 6px;
  background: #ffffff;
}

.rfp-analysis-panel ul,
.rfp-analysis-panel ol {
  margin: 6px 0 0;
  padding-left: 18px;
}

.rfp-analysis-panel li {
  margin-bottom: 5px;
}

.rfp-analysis-panel li small {
  display: block;
  color: #526171;
  font-size: 11px;
  line-height: 1.35;
}

.snippet-card {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 8px;
  align-items: center;
  padding: 8px;
  border: 1px solid #d8e0e8;
  background: #ffffff;
}

.snippet-card div {
  display: grid;
  gap: 2px;
  min-width: 0;
}

.snippet-card strong,
.snippet-card small {
  min-width: 0;
  overflow-wrap: anywhere;
}

.callout-palette {
  border-left-color: #8a1538;
  background: #fffafa;
}

.chart-designer {
  border-left-color: #246064;
  background: #f7fcfc;
}

.chart-designer-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(145px, 1fr));
  gap: 8px;
}

.chart-designer textarea,
.chart-designer input,
.chart-designer select {
  width: 100%;
}

.chart-designer pre {
  max-height: 260px;
  overflow: auto;
  margin: 6px 0 0;
  padding: 8px;
  border: 1px solid #d8e0e8;
  background: #ffffff;
  white-space: pre-wrap;
}

.callout-selector {
  display: grid;
  grid-template-columns: minmax(150px, 220px) minmax(0, 1fr);
  gap: 8px;
  align-items: end;
}

.callout-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(210px, 1fr));
  gap: 8px;
}

.callout-card {
  display: grid;
  gap: 8px;
  padding: 9px;
  border: 1px solid #d8e0e8;
  border-left: 4px solid #526171;
  border-radius: 7px;
  background: #ffffff;
}

.callout-card[data-tone="positive"] {
