}

.callout-card[data-tone="caution"] {
  border-left-color: #b7791f;
}

.callout-card[data-tone="critical"] {
  border-left-color: #b42318;
}

.callout-card[data-tone="evidence"] {
  border-left-color: #275da8;
}

.callout-card[data-tone="action"] {
