  line-height: 1.35;
}

.callout-card pre {
  max-height: 130px;
  overflow: auto;
  margin: 0;
  padding: 8px;
  border: 1px solid #d8e0e8;
  background: #f8fafc;
  white-space: pre-wrap;
}

.app-shell[data-theme="dark"] .callout-palette,
.app-shell[data-theme="dark"] .chart-designer,
.app-shell[data-theme="dark"] .callout-card {
  border-color: #34465a;
