}

.app-shell[data-theme="dark"] .callout-card pre {
  border-color: #34465a;
  background: #111821;
}

.app-shell[data-theme="dark"] .chart-designer pre {
  border-color: #34465a;
  background: #111821;
}

@media (prefers-color-scheme: dark) {
  .app-shell[data-theme="system"] .callout-palette,
  .app-shell[data-theme="system"] .chart-designer,
  .app-shell[data-theme="system"] .callout-card {
    border-color: #34465a;
    background: #1b2736;
    color: #dce7f3;
  }

  .app-shell[data-theme="system"] .callout-card small {
    color: #aebdcc;
  }

  .app-shell[data-theme="system"] .callout-card pre {
    border-color: #34465a;
    background: #111821;
  }

  .app-shell[data-theme="system"] .chart-designer pre {
    border-color: #34465a;
    background: #111821;
  }
}

.business-profile-modal {
