}

.template-card-header small {
  color: #526171;
  line-height: 1.35;
}

.template-source {
  align-self: start;
  padding: 2px 6px;
  border: 1px solid #c7d5e5;
  border-radius: 999px;
  background: #f2f7fc;
  color: #31516f;
  font-size: 10px;
  font-weight: 700;
  line-height: 1.3;
  text-transform: uppercase;
}

.template-meta {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 6px;
}

.template-meta-summary {
  flex: 1 0 100%;
