}

.template-meta span {
  padding: 2px 7px;
  border: 1px solid #d8e0e8;
  border-radius: 999px;
  background: #f8fafc;
  color: #44566a;
  font-size: 11px;
  font-weight: 650;
}

.template-card pre {
