}

.template-tags small {
  padding: 2px 6px;
  border: 1px solid #d8e0e8;
  background: #f8fafc;
}

.template-actions button {
  min-height: 28px;
  padding: 3px 8px;
}

.export-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin: 8px 0 10px;
}

.brand-kit-manager {
  display: grid;
  gap: 10px;
  padding: 10px;
  border: 1px solid #c9d2dc;
  border-left: 3px solid #174a7c;
  border-radius: 7px;
  background: #ffffff;
}

.brand-kit-manager > header,
.brand-kit-card > header,
.brand-kit-preview > header {
