  white-space: nowrap;
}

.configuration-center-panel {
  margin-bottom: 12px;
}

.transform-handler-installer {
  display: grid;
  gap: 10px;
  padding: 10px;
  border: 1px solid #c9d2dc;
  border-radius: 8px;
  background: #f8fafc;
}

.transform-handler-installer header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 10px;
}

.transform-handler-installer header div {
  display: grid;
  gap: 3px;
}

.transform-handler-installer h4 {
  margin: 0;
  color: #182433;
  font-size: 13px;
}

.transform-handler-installer header span,
.transform-handler-installer dd,
.transform-handler-installer li {
  color: #526171;
  font-size: 11px;
}

.transform-installer-summary {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(130px, 1fr));
  gap: 8px;
  margin: 0;
}

.transform-installer-summary div {
  display: grid;
  gap: 2px;
  min-width: 0;
}

.transform-installer-summary dt {
  color: #36465a;
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
}

.transform-installer-summary dd {
  margin: 0;
}

.transform-installer-handlers {
  display: grid;
  gap: 3px;
  margin: 0;
  padding-left: 18px;
}

.support-bundle-recommendations {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 8px;
}

.support-bundle-recommendations article {
  display: grid;
  gap: 6px;
  padding: 8px;
  border: 1px solid #d8e0e8;
  border-radius: 6px;
  background: #ffffff;
}

.support-bundle-recommendations article[data-priority="blocker"] {
  border-color: #d9a76c;
  background: #fff8ed;
}

.support-bundle-recommendations article[data-priority="handoff"] {
  border-color: #b9c8de;
  background: #f5f8fc;
}

.support-bundle-recommendations header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.support-bundle-recommendations header span {
  color: #182433;
  font-size: 11px;
  font-weight: 800;
  text-transform: uppercase;
}

.support-bundle-recommendations header small {
  color: #526171;
  font-size: 10px;
}

.support-bundle-recommendations ul {
  display: grid;
  gap: 4px;
  margin: 0;
  padding-left: 18px;
}

.support-bundle-recommendations li {
  color: #526171;
  font-size: 11px;
}

.app-shell[data-theme="dark"] .support-bundle-recommendations article,
.app-shell[data-theme="dark"] .support-bundle-action-plan article {
  border-color: #34465a;
  background: #1b2736;
}

.app-shell[data-theme="dark"] .support-bundle-recommendations article[data-priority="blocker"] {
  border-color: #7c5f38;
  background: #2a251d;
}

.app-shell[data-theme="dark"] .support-bundle-recommendations article[data-priority="handoff"] {
  border-color: #405267;
  background: #1d2a3a;
}

.app-shell[data-theme="dark"] .support-bundle-recommendations header span,
.app-shell[data-theme="dark"] .support-bundle-action-plan h5,
.app-shell[data-theme="dark"] .support-bundle-action-plan strong {
  color: #e6edf5;
}

.app-shell[data-theme="dark"] .support-bundle-recommendations header small,
.app-shell[data-theme="dark"] .support-bundle-recommendations li,
.app-shell[data-theme="dark"] .support-bundle-action-plan span,
.app-shell[data-theme="dark"] .support-bundle-action-plan small {
  color: #b7c4d3;
}

.support-bundle-action-plan {
  display: grid;
  gap: 6px;
}

.support-bundle-action-plan h5 {
  margin: 0;
  color: #182433;
  font-size: 12px;
}

.support-bundle-action-plan article {
  display: grid;
  gap: 3px;
  padding: 7px 8px;
  border: 1px solid #d8e0e8;
  border-radius: 6px;
  background: #ffffff;
}

.support-bundle-action-plan strong {
  color: #182433;
  font-size: 11px;
}

.support-bundle-action-plan span,
.support-bundle-action-plan small {
  color: #526171;
  font-size: 11px;
}

.transform-installer-commands {
  max-height: 150px;
