  padding: 8px;
  overflow: auto;
  border: 1px solid #d8e0e8;
  border-radius: 6px;
  background: #ffffff;
  color: #1f2937;
  font-size: 11px;
  white-space: pre-wrap;
}

.agent-provider-output {
  display: grid;
  gap: 10px;
  background: #f8fafc;
}

.agent-provider-output ul {
  display: grid;
  gap: 4px;
  margin: 0;
  padding-left: 18px;
  color: #2d3746;
  font-size: 12px;
}

.local-agent-handoff-details {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(210px, 1fr));
  gap: 8px;
  margin: 0;
}

.local-agent-handoff-details div {
  min-width: 0;
}

.local-agent-handoff-details dt {
  color: #526171;
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
}

.local-agent-handoff-details dd {
  margin: 2px 0 0;
  overflow-wrap: anywhere;
  color: #17202d;
  font-size: 12px;
}

.export-target-options label {
  margin-bottom: 0;
}

.template-action-primary {
  border-color: #7fa2cd;
  background: #eaf3ff;
  color: #143f70;
  font-weight: 700;
}

.danger-action {
  border-color: #e3b7b7;
  background: #fff5f5;
  color: #9b1c1c;
}

.button-icon {
  display: inline-flex;
  width: 16px;
  height: 16px;
  flex: 0 0 16px;
}

.button-icon svg {
  width: 16px;
  height: 16px;
}

.custom-template-editor {
  margin-top: 14px;
  padding-top: 12px;
  border-top: 1px solid #d8e0e8;
}

.crop-focus-pad {
  position: relative;
  width: 100%;
  min-height: 128px;
  overflow: hidden;
  border: 1px solid #9fb0c2;
  background:
    linear-gradient(rgba(255, 255, 255, 0.72), rgba(255, 255, 255, 0.72)),
    repeating-linear-gradient(45deg, #e6ecf3 0 8px, #f7f9fb 8px 16px);
  background-repeat: no-repeat;
  background-size: cover;
  cursor: crosshair;
  touch-action: none;
}

.crop-focus-pad::before {
  position: absolute;
  inset: 0;
  background:
    linear-gradient(to right, transparent 33%, rgba(15, 23, 42, 0.32) 33% 34%, transparent 34% 66%, rgba(15, 23, 42, 0.32) 66% 67%, transparent 67%),
    linear-gradient(to bottom, transparent 33%, rgba(15, 23, 42, 0.32) 33% 34%, transparent 34% 66%, rgba(15, 23, 42, 0.32) 66% 67%, transparent 67%);
  content: "";
}

.crop-focus-pad:focus-visible {
  outline: 2px solid #2f6f9f;
  outline-offset: 2px;
}

.crop-focus-pad.disabled {
  cursor: not-allowed;
  opacity: 0.58;
}

.crop-focus-point,
.crop-focus-reticle {
  position: absolute;
  z-index: 1;
  transform: translate(-50%, -50%);
  pointer-events: none;
}

.crop-focus-point {
  width: 5px;
  height: 5px;
  border-radius: 50%;
  background: rgba(15, 23, 42, 0.55);
}

.crop-focus-reticle {
  width: 20px;
  height: 20px;
  border: 2px solid #ffffff;
  border-radius: 50%;
  background: #2f6f9f;
  box-shadow: 0 0 0 2px rgba(15, 23, 42, 0.72);
}

.engine-row {
  display: grid;
  gap: 8px;
  margin: 8px 0;
  padding: 8px;
  border: 1px solid #c9d2dc;
  background: #ffffff;
}

.engine-row h4 {
  margin: 0;
  font-size: 13px;
}

.engine-setup-status {
  margin: 0;
  padding: 6px 8px;
  border-left: 3px solid #64748b;
  background: #f8fafc;
}

.engine-setup-status.fallback,
.engine-setup-status.needs-trust {
  border-left-color: #b45309;
  background: #fffbeb;
}

.engine-setup-status.ready {
  border-left-color: #2f855a;
  background: #f0fdf4;
}

.engine-setup-status.disabled {
  border-left-color: #6b7280;
  background: #f3f4f6;
}

.engine-probe {
  border-left: 3px solid #64748b;
  padding: 6px 8px;
  background: #f8fafc;
}

.engine-probe.ok {
  border-left-color: #2f855a;
}

.engine-probe.failed {
