}

.engine-probe p,
.engine-probe ul {
  margin: 4px 0 0;
}

.path-picker {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 6px;
}

.path-picker input {
  min-width: 0;
}

.formula-cell {
  font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;
  color: #7c2d12;
  background: #fff7ed;
}

.engine-summary {
  margin: 4px 0;
  color: #526171;
  font-size: 12px;
}

.table-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin-bottom: 12px;
}

.table-two-way-strip {
  display: grid;
  gap: 8px;
  margin-bottom: 12px;
  padding: 8px;
  border: 1px solid #d8e0e8;
  background: #f8fafc;
}

.table-two-way-strip header {
  display: flex;
  justify-content: space-between;
  gap: 8px;
  align-items: flex-start;
}

.table-two-way-strip header div {
  display: grid;
  gap: 2px;
  min-width: 0;
}

.table-two-way-strip strong {
  font-size: 13px;
}

.table-two-way-strip header span:not(.table-sync-chip) {
  color: #526171;
  font-size: 12px;
}

.table-two-way-actions {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(118px, 1fr));
  gap: 6px;
}

.table-follow-source-toggle {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  min-height: 30px;
  padding: 5px 7px;
  border: 1px solid #d8e0e8;
  background: #fff;
  color: #1b2733;
  font-size: 12px;
}

.table-sync-chip {
  display: inline-flex;
  justify-content: center;
  align-items: center;
  min-height: 30px;
  padding: 5px 8px;
  border: 1px solid #d8e0e8;
  background: #fff;
  color: #1b2733;
  font-size: 12px;
  font-weight: 700;
  text-align: center;
}

.table-sync-chip.ready {
  border-color: #86efac;
  background: #f0fdf4;
  color: #166534;
}

.table-sync-chip.attention {
  border-color: #facc15;
  background: #fefce8;
  color: #854d0e;
}

.table-sync-chip.error {
  border-color: #fecaca;
  background: #fff7f7;
  color: #b91c1c;
}

.table-cell-text-editor {
  display: grid;
  gap: 6px;
  margin-bottom: 12px;
  padding: 8px;
  border: 1px solid #d8e0e8;
  background: #f8fafc;
}

.table-cursor-cell {
  margin: 0;
