  font-size: 12px;
}

.table-issues .error {
  color: #b91c1c;
}

.table-issues .warning {
  color: #92400e;
}

.table-editor-grid {
  display: grid;
  gap: 4px;
  min-width: 680px;
  align-items: center;
}

.table-editor-grid input,
.table-editor-grid select,
.table-editor-grid button,
.table-editor-grid output {
  width: 100%;
  min-width: 0;
}

.table-editor-grid output {
  min-height: 30px;
  padding: 6px 8px;
  border: 1px solid #d8e0e8;
  background: #f5f7fa;
  color: #1b2733;
  font-variant-numeric: tabular-nums;
}

.table-editor-grid span {
  color: #526171;
  font-size: 12px;
}

.table-editor-grid .row-actions,
.table-editor-grid .column-actions {
  display: grid;
  gap: 4px;
}

.table-editor-grid .row-actions {
  grid-template-columns: repeat(4, minmax(0, 1fr));
}

.table-editor-grid .column-actions {
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.table-preview {
  margin-top: 12px;
}

.table-preview textarea {
  font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;
  white-space: pre;
}

.table-source-editor textarea[aria-invalid="true"] {
  border-color: #b91c1c;
  background: #fff7f7;
}

.table-source-error {
  margin: -6px 0 12px;
  color: #b91c1c;
  font-size: 12px;
}

.editor-pane {
  background: #ffffff;
  overflow: hidden;
}

.workspace-writing-maximized .editor-pane {
  border-right: 0;
}

.editor-split-grid {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  height: 100%;
  min-width: 0;
  min-height: 0;
}

.editor-split-grid[data-split-source="true"] {
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.editor-host {
  height: 100%;
  min-width: 0;
  min-height: 0;
}

.editor-host-secondary {
  border-left: 1px solid #d7dee7;
}

.preview-pane {
  background: #ffffff;
}

.preview-pane[data-preview-theme="dark"] {
  background: #0f172a;
}

.preview-pane[data-preview-theme="dark"] .preview-document {
  color: #dbeafe;
  background: #111827;
}

.preview-pane[data-preview-theme="dark"] .preview-document h1,
.preview-pane[data-preview-theme="dark"] .preview-document h2,
.preview-pane[data-preview-theme="dark"] .preview-document h3 {
  color: #f8fafc;
}

.preview-pane[data-preview-theme="dark"] .preview-document pre {
  background: #0b1220;
  color: #e5e7eb;
}

.preview-pane[data-preview-theme="light"] {
  background: #ffffff;
}

.preview-pane[data-preview-theme="light"] .preview-document {
  color: #1f2937;
  background: #ffffff;
}

.preview-document {
  max-width: 900px;
  margin: 0 auto;
  padding: 48px;
  color: #1f2937;
  line-height: 1.65;
}

.preview-document.print-preview-document {
  max-width: 794px;
  min-height: 1123px;
  padding: 72px;
  border: 1px solid #cbd5e1;
  box-shadow: 0 12px 36px rgba(15, 23, 42, 0.18);
  background:
    linear-gradient(#ffffff, #ffffff) padding-box,
    repeating-linear-gradient(to bottom, transparent 0, transparent 1040px, rgba(111, 78, 0, 0.18) 1041px, rgba(111, 78, 0, 0.18) 1042px) border-box;
}

.preview-document h1,
.preview-document h2,
.preview-document h3 {
  color: #111827;
  line-height: 1.2;
}

.preview-document p,
.preview-document li,
.preview-document blockquote {
  orphans: 2;
  widows: 2;
}

.preview-document table,
.transform-table {
  width: 100%;
  border-collapse: collapse;
}

.preview-document td,
.preview-document th,
.transform-table td,
.transform-table th {
  border: 1px solid #c9d2dc;
  padding: 6px 8px;
}

.preview-document td.numeric,
.preview-document th.numeric,
.transform-table td.numeric,
.transform-table th.numeric {
  text-align: right;
  font-variant-numeric: tabular-nums;
}

.preview-document td.numeric.negative,
.transform-table td.numeric.negative {
  color: #9f1239;
}

.preview-document figure[data-float="right"],
.preview-document .figure-float-right {
  float: right;
  max-width: 45%;
  margin: 0 0 16px 24px;
}

.preview-document figure[data-float="left"],
.preview-document .figure-float-left {
  float: left;
  max-width: 45%;
  margin: 0 24px 16px 0;
}

.preview-document figure[data-fit="cover"] img,
.preview-document .figure-fit-cover img {
  width: 100%;
  aspect-ratio: 16 / 9;
  object-fit: cover;
}

.preview-document figure[data-position="top"] img,
.preview-document .figure-position-top img {
  object-position: center top;
}

.preview-document figure[data-position="bottom"] img,
.preview-document .figure-position-bottom img {
  object-position: center bottom;
}

.preview-document figure[data-position="left"] img,
.preview-document .figure-position-left img {
  object-position: left center;
}

.preview-document figure[data-position="right"] img,
.preview-document .figure-position-right img {
  object-position: right center;
}

.preview-document figure[data-position="top-left"] img,
.preview-document .figure-position-top-left img {
  object-position: left top;
}

.preview-document figure[data-position="top-right"] img,
.preview-document .figure-position-top-right img {
  object-position: right top;
}

.preview-document figure[data-position="bottom-left"] img,
.preview-document .figure-position-bottom-left img {
  object-position: left bottom;
}

.preview-document figure[data-position="bottom-right"] img,
.preview-document .figure-position-bottom-right img {
  object-position: right bottom;
}

.preview-document .glossary-term {
  border-bottom: 1px dotted #275da8;
  color: #174a8c;
  cursor: help;
  text-decoration: none;
}

.preview-document .glossary-term:focus {
  outline: 2px solid #275da8;
  outline-offset: 2px;
}

.preview-document .citation {
  color: #174a8c;
  cursor: help;
  font-weight: 600;
  position: relative;
}

.preview-document .citation:focus {
  outline: 2px solid #275da8;
  outline-offset: 2px;
}

.preview-document [data-preview-source-target] {
  cursor: pointer;
}

.preview-document [data-preview-source-target]:focus-visible {
  outline: 3px solid #2563eb;
  outline-offset: 4px;
}

.preview-document .citation[data-citation-detail]:hover::after,
.preview-document .citation[data-citation-detail]:focus::after {
  content: attr(data-citation-detail);
  position: absolute;
  left: 0;
  bottom: calc(100% + 6px);
  z-index: 20;
  width: max-content;
  max-width: min(320px, 80vw);
  white-space: normal;
  background: #111827;
  color: #ffffff;
  border: 1px solid #374151;
  border-radius: 4px;
  box-shadow: 0 12px 24px rgba(15, 23, 42, 0.22);
  padding: 8px 10px;
  font-size: 0.84rem;
  line-height: 1.35;
  font-weight: 500;
}

.preview-document .callout {
  border-left: 4px solid #1f6f55;
  background: #eefaf4;
  padding: 10px 12px;
  margin: 14px 0;
}

.preview-document .callout strong {
  display: block;
  color: #0f5132;
  margin-bottom: 4px;
}

.preview-document .callout-decision,
.preview-document .callout-action {
  border-left-color: #6f4e00;
  background: #fff8e6;
}

.preview-document .callout-decision strong,
.preview-document .callout-action strong {
  color: #5a3b00;
}

.preview-document .callout-recommendation {
  border-left-color: #1f6f55;
  background: #eefaf4;
}

.preview-document .callout-risk,
.preview-document .callout-warning {
  border-left-color: #b42318;
  background: #fff4f2;
}

.preview-document .callout-risk strong,
.preview-document .callout-warning strong {
  color: #7a271a;
}

.preview-document .callout-assumption {
  border-left-color: #526171;
  background: #f5f7fa;
}

.preview-document .callout-assumption strong {
  color: #2d3746;
}

.preview-document .callout-evidence {
  border-left-color: #275da8;
  background: #eff6ff;
}

.preview-document .callout-evidence strong {
  color: #174a7c;
}

.preview-document .equation {
  margin: 18px 0;
}

.preview-document .math-rendered {
  font-family: Georgia, "Times New Roman", serif;
  font-size: 1.08em;
}

.preview-document .math-display {
  padding: 12px;
  border: 1px solid #d8e0e8;
  background: #f8fafc;
  text-align: center;
}

.preview-document .math-frac {
  display: inline-grid;
  grid-template-rows: auto auto;
  vertical-align: middle;
  text-align: center;
}

.preview-document .math-frac span:first-child {
  border-bottom: 1px solid currentColor;
}

.preview-document .math-sqrt::before {
  content: "√";
}

.preview-document .math-root-index {
  font-size: 0.65em;
  vertical-align: super;
}

.preview-document .math-text {
  font-family: inherit;
}

.preview-document .math-blackboard {
  font-family: Georgia, "Times New Roman", serif;
  font-weight: 700;
}

.preview-document .math-calligraphic {
  font-family: "Snell Roundhand", "Apple Chancery", cursive;
}

.preview-document .math-roman {
  font-family: Georgia, "Times New Roman", serif;
  font-style: normal;
}

.preview-document .math-hat::before,
.preview-document .math-vec::before {
  display: block;
  height: 0;
  line-height: 0;
  text-align: center;
}

.preview-document .math-hat::before {
  content: "^";
}

.preview-document .math-vec::before {
  content: "→";
}

.preview-document .math-overline {
  border-top: 1px solid currentColor;
}

.preview-document .math-underline {
  border-bottom: 1px solid currentColor;
}

.preview-document .math-align-separator {
  display: inline-block;
  min-width: 1ch;
}

.preview-document .math-matrix {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  vertical-align: middle;
}

.preview-document .math-matrix::before,
.preview-document .math-matrix::after {
  font-size: 1.8em;
  line-height: 1;
}

.preview-document .math-matrix.matrix-round::before {
  content: "(";
}

.preview-document .math-matrix.matrix-round::after {
  content: ")";
}

.preview-document .math-matrix.matrix-square::before {
  content: "[";
}

.preview-document .math-matrix.matrix-square::after {
  content: "]";
}

.preview-document .math-matrix.matrix-vertical::before,
.preview-document .math-matrix.matrix-vertical::after {
  content: "|";
}

.preview-document .math-matrix.matrix-cases::before {
  content: "{";
}

.preview-document .math-matrix.matrix-cases::after {
  content: "";
}

.preview-document .math-matrix table {
  width: auto;
  border-collapse: collapse;
  display: inline-table;
}

.preview-document .math-matrix td {
  border: 0;
  padding: 0 0.45ch;
  text-align: center;
}

.preview-document .math-source-inline {
  position: absolute;
  width: 1px;
  height: 1px;
  overflow: hidden;
  clip: rect(0 0 0 0);
}

.preview-document pre,
.sidebar pre {
  overflow: auto;
  padding: 10px;
  background: #edf1f5;
}

.transform-calc {
  padding: 10px;
  border: 1px solid #c9d2dc;
  background: #f7f9fb;
}

.status-bar {
  justify-content: space-between;
  gap: 8px;
  overflow-x: auto;
  overflow-y: hidden;
  border-top: 1px solid #c9d2dc;
  border-bottom: 0;
  background: #f8fafc;
  white-space: nowrap;
}

.status-message,
.word-stats,
.preview-timing,
.watch-status,
.export-progress,
.error {
  display: inline-flex;
  align-items: center;
  min-height: 20px;
  min-width: 0;
  padding: 1px 7px;
  border: 1px solid transparent;
  border-radius: 999px;
  overflow: hidden;
  text-overflow: ellipsis;
}

.status-message {
  max-width: 36vw;
  border-color: #d9e1ea;
  background: #ffffff;
  color: #324156;
}

.word-stats,
.preview-timing,
.watch-status,
.export-progress {
  background: #eef3f8;
  color: #4a5b6d;
}

.conflict-actions,
.compile-actions {
  display: inline-flex;
  align-items: center;
  gap: 6px;
}

.error {
  border-color: #efc7c7;
  background: #fff5f5;
  color: #c24141;
}

.modal-backdrop {
  position: fixed;
  inset: 0;
  display: grid;
  place-items: center;
  padding: 24px;
  background: rgba(15, 23, 42, 0.38);
  z-index: 20;
}

.modal {
  display: grid;
  gap: 12px;
  width: min(720px, 100%);
  max-height: min(760px, 92vh);
  overflow: auto;
  padding: 16px;
  border: 1px solid #bac4d1;
  border-radius: 8px;
  background: #f7f9fb;
  box-shadow: 0 20px 60px rgba(15, 23, 42, 0.28);
}

.modal header,
.modal footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.modal h2 {
  margin: 0;
  font-size: 18px;
}

.docs-live-modal {
  width: min(1120px, 100%);
}

.docs-live-wizard-shell,
.docs-live-wizard-panel {
  display: grid;
  gap: 12px;
}

.docs-live-stepper {
  display: grid;
  grid-template-columns: repeat(5, minmax(0, 1fr));
  gap: 8px;
  padding: 6px;
  border: 1px solid #d7dee7;
  border-radius: 8px;
  background: #eef3f8;
}

.docs-live-stepper button {
  display: grid;
  grid-template-columns: 22px minmax(0, 1fr);
  grid-template-rows: auto auto;
  align-items: center;
  justify-content: start;
  gap: 2px 7px;
  min-height: 48px;
  padding: 6px 8px;
  text-align: left;
}

.docs-live-stepper button span {
  grid-row: 1 / span 2;
  display: inline-grid;
  place-items: center;
  width: 22px;
  height: 22px;
  border-radius: 999px;
  background: #dce6f0;
  color: #24445f;
  font-size: 11px;
  font-weight: 850;
}

.docs-live-stepper button strong,
.docs-live-stepper button small {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.docs-live-stepper button strong {
  font-size: 12px;
}

.docs-live-stepper button small {
  color: #526171;
  font-size: 10px;
}

.docs-live-stepper button.active {
  border-color: #315f8d;
  background: #ffffff;
  box-shadow: 0 0 0 3px rgba(75, 119, 166, 0.15);
}

.docs-live-stepper button.complete span,
.docs-live-stepper button.active span {
  background: #315f8d;
  color: #ffffff;
}

.docs-live-grid {
  display: grid;
  grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);
  gap: 12px;
}

.docs-live-grid-compact {
  grid-template-columns: minmax(180px, 1fr) minmax(220px, 1.2fr) minmax(160px, 0.8fr);
}

.docs-live-grid label,
.docs-live-voice,
.docs-live-context-grid label,
.docs-live-outline-tools label,
.docs-live-draft-settings label {
  display: grid;
  gap: 6px;
  min-width: 0;
}

.docs-live-wide,
.docs-live-preview {
  grid-column: 1 / -1;
}

.docs-live-voice {
  padding: 10px;
  border: 1px solid #d7dee7;
  border-radius: 8px;
  background: #eef3f8;
}

.docs-live-voice-actions,
.docs-live-preview header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
}

.docs-live-draft-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  justify-content: flex-end;
}

.docs-live-draft-actions button {
  min-height: 28px;
  padding: 4px 8px;
  font-size: 11px;
}

.docs-live-voice-actions span,
.docs-live-preview span {
  color: #526171;
  font-size: 12px;
}

.docs-live-runtime {
  display: grid;
  gap: 8px;
  padding: 8px;
  border: 1px solid #d7dee7;
  border-left: 3px solid #4f7f55;
  border-radius: 6px;
  background: #ffffff;
}

.docs-live-runtime header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.docs-live-runtime header span,
.docs-live-runtime li {
  color: #526171;
  font-size: 12px;
}

.docs-live-runtime ul {
  display: grid;
  gap: 4px;
  margin: 0;
  padding-left: 18px;
}

.docs-live-type-card,
.docs-live-suggested-outline,
.docs-live-draft-settings {
  display: grid;
  gap: 10px;
  padding: 10px;
  border: 1px solid #d7dee7;
  border-radius: 8px;
  background: #ffffff;
}

.docs-live-type-card header,
.docs-live-suggested-outline header {
  display: flex;
  justify-content: space-between;
  gap: 10px;
  align-items: start;
}

.docs-live-type-card header span,
.docs-live-type-card header small,
.docs-live-suggested-outline header span {
  color: #526171;
  font-size: 12px;
}

.docs-live-outline-link {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 12px;
  color: #344054;
}

.docs-live-outline-link input {
  margin: 0;
}

.docs-live-profile-lists,
.docs-live-outline-tools,
.docs-live-context-grid {
  display: grid;
  grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);
  gap: 12px;
}

.docs-live-profile-lists section {
  display: grid;
  gap: 6px;
}

.docs-live-profile-lists ul {
  display: grid;
  gap: 4px;
  margin: 0;
  padding-left: 18px;
  color: #526171;
  font-size: 12px;
}

.docs-live-outline-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.docs-live-intent-brief,
.docs-live-placeholder-manager,
.docs-live-suggestions {
  display: grid;
  gap: 8px;
  padding: 10px;
  border: 1px solid #d7dee7;
  border-radius: 8px;
  background: #ffffff;
}

.docs-live-intent-brief header,
.docs-live-suggestions header {
  display: flex;
  justify-content: space-between;
  gap: 12px;
  align-items: start;
}

.docs-live-intent-brief header span,
.docs-live-intent-brief header small,
.docs-live-suggestions header span,
.docs-live-suggestions article span,
.docs-live-suggestions article small {
  color: #526171;
  font-size: 12px;
}

.docs-live-intent-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
  gap: 8px;
}

.docs-live-intent-grid label {
  display: grid;
  gap: 5px;
}

.docs-live-intent-grid label small {
  color: #667789;
  font-size: 10px;
  line-height: 1.25;
}

.docs-live-placeholder-manager header,
.docs-live-placeholder-add,
.docs-live-placeholder-grid [role="row"] {
  display: grid;
  gap: 8px;
  align-items: end;
}

.docs-live-placeholder-manager header {
  grid-template-columns: 1fr;
}

.docs-live-placeholder-manager header span {
  color: #526171;
  font-size: 12px;
}

.docs-live-placeholder-add {
  grid-template-columns: minmax(105px, 0.55fr) minmax(150px, 1fr) minmax(110px, 0.55fr) minmax(150px, 1fr) minmax(120px, 0.6fr) auto;
}

.docs-live-placeholder-grid {
  display: grid;
  gap: 4px;
}

.docs-live-placeholder-grid [role="row"] {
  grid-template-columns: minmax(90px, 0.45fr) minmax(150px, 1fr) minmax(105px, 0.55fr) minmax(150px, 1fr) minmax(115px, 0.6fr) auto;
}

.docs-live-placeholder-head {
  color: #526171;
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
}

.docs-live-suggestions article {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 10px;
  align-items: start;
  padding: 8px;
  border: 1px solid #e3e8ef;
  border-radius: 6px;
  background: #f8fafc;
}

.docs-live-suggestions article div {
  display: grid;
  gap: 4px;
}

.docs-live-suggestions article p {
  margin: 0;
  color: #17212d;
  font-size: 13px;
  line-height: 1.45;
}

.docs-live-suggestions article ul {
  margin: 0;
  padding-left: 18px;
  color: #526171;
  font-size: 12px;
  line-height: 1.4;
}

.docs-live-workflow {
  display: grid;
  gap: 10px;
  padding: 10px;
  border: 1px solid #cbd5df;
  border-radius: 8px;
  background: #ffffff;
}

.docs-live-workflow header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
}

.docs-live-workflow header span,
.docs-live-section-cards span {
  color: #526171;
  font-size: 12px;
}

.docs-live-workflow > ol {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
  gap: 8px;
  margin: 0;
  padding: 0;
  list-style: none;
}

.docs-live-workflow > ol > li,
.docs-live-section-cards article {
  display: grid;
  gap: 4px;
  min-width: 0;
  padding: 8px;
  border: 1px solid #d7dee7;
  border-radius: 6px;
  background: #f7f9fb;
}

.docs-live-workflow > ol > li[data-status="needs-input"] {
  border-color: #c58a18;
  background: #fff8e8;
}

.docs-live-workflow li small {
  color: #526171;
  font-size: 11px;
  text-transform: uppercase;
}

.docs-live-workflow li span,
.docs-live-section-cards p {
  margin: 0;
  color: #2d3746;
  font-size: 12px;
  line-height: 1.4;
}

.docs-live-workflow li p,
.docs-live-workflow li em {
  margin: 0;
  font-size: 11px;
  line-height: 1.4;
}

.docs-live-workflow li p {
  color: #18324f;
}

.docs-live-workflow li em {
  color: #6b7280;
  font-style: normal;
}

.docs-live-section-cards {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
  gap: 8px;
}

.docs-live-section-stage-list {
  display: grid;
  gap: 6px;
  margin: 4px 0 0;
  padding: 0;
  list-style: none;
}

.docs-live-section-stage-list li {
  display: grid;
  gap: 2px;
  padding-top: 6px;
  border-top: 1px solid #d7dee7;
}

.docs-live-section-stage-list li[data-status="needs-review"] strong {
  color: #7a5308;
}

.docs-live-review-packet {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(190px, 1fr));
  gap: 8px;
}

.docs-live-review-packet-header {
  grid-column: 1 / -1;
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 10px;
  padding: 8px;
  border: 1px solid #d7dee7;
  border-radius: 6px;
  background: #f8fafc;
}

.docs-live-review-packet-header div:first-child {
  display: grid;
  gap: 2px;
  min-width: 0;
}

.docs-live-review-packet-header span {
  color: #526071;
  font-size: 12px;
  line-height: 1.35;
}

.docs-live-review-actions {
  display: flex;
  flex-wrap: wrap;
  justify-content: flex-end;
  gap: 6px;
  flex: 0 0 auto;
}

.docs-live-review-packet section {
  display: grid;
  gap: 6px;
  min-width: 0;
  padding: 8px;
  border: 1px solid #d7dee7;
  border-radius: 6px;
  background: #ffffff;
}

.docs-live-review-packet ul,
.docs-live-review-packet ol {
  display: grid;
  gap: 4px;
  margin: 0;
  padding-left: 18px;
  color: #2d3746;
  font-size: 12px;
  line-height: 1.4;
}

.docs-live-preview {
  display: grid;
  gap: 8px;
}

.docs-live-history {
  display: grid;
  gap: 8px;
}

.docs-live-history > header,
.docs-live-history article {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 10px;
  padding: 8px;
  border: 1px solid #d7dee7;
  border-radius: 6px;
  background: #ffffff;
}

.docs-live-history > header {
  background: #f8fafc;
}

.docs-live-history article > div:first-child,
.docs-live-history > header > div {
  display: grid;
  gap: 3px;
  min-width: 0;
}

.docs-live-history span,
.docs-live-history p {
  margin: 0;
  color: #526071;
  font-size: 12px;
  line-height: 1.35;
}

.docs-live-history-actions {
  display: flex;
  flex-wrap: wrap;
  justify-content: flex-end;
  gap: 6px;
  flex: 0 0 min(260px, 40%);
}

.modal textarea,
.modal input,
.modal select {
  width: 100%;
  border: 1px solid #bac4d1;
  border-radius: 6px;
  padding: 10px;
  color: #18212f;
  background: #ffffff;
}

.command-modal {
  align-content: start;
}

.command-agent-route {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 12px;
  align-items: center;
  border: 1px solid #b9d4ec;
  border-left: 3px solid #275da8;
  border-radius: 6px;
  padding: 10px;
  background: #f5faff;
}

.command-agent-route > div,
.command-agent-actions {
  display: grid;
  gap: 6px;
}

.command-agent-route span {
  color: #526171;
  font-size: 12px;
}

.command-agent-preview {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 6px;
  margin: 4px 0 0;
}

.command-agent-preview div {
  min-width: 0;
}

.command-agent-preview dt {
  color: #526171;
  font-size: 10px;
  font-weight: 800;
  text-transform: uppercase;
}

.command-agent-preview dd {
  margin: 0;
  overflow-wrap: anywhere;
  font-size: 12px;
}

.command-agent-routes {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.command-agent-routes button {
  font-size: 11px;
  padding: 5px 8px;
}

.command-row {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 16px;
  width: 100%;
  padding: 8px 10px;
  text-align: left;
}

.command-row-main {
  display: grid;
  gap: 2px;
  min-width: 0;
}

.command-row-main small {
  color: #526171;
  font-size: 11px;
  line-height: 1.35;
}

.command-row > span:last-child {
  color: #526171;
  font-size: 12px;
}

.conflict-modal {
  width: min(1100px, 100%);
}

.conflict-path {
  margin: -4px 0 0;
  overflow-wrap: anywhere;
  color: #526171;
  font-family: "SFMono-Regular", Consolas, monospace;
  font-size: 12px;
}

.compare-grid {
  display: grid;
  grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);
  gap: 12px;
  min-height: 0;
}

.field-with-action {
  display: grid;
  gap: 6px;
  min-width: 0;
}

.field-action-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.field-action-header button {
  min-height: 28px;
  padding: 3px 8px;
  font-size: 12px;
}

.compare-grid pre {
  max-height: 420px;
  overflow: auto;
  padding: 10px;
  background: #edf1f5;
}

.conflict-merge {
  display: grid;
  gap: 12px;
}

.conflict-toolbar {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.conflict-diff {
  display: grid;
  grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);
  max-height: 320px;
  overflow: auto;
  border: 1px solid #c9d2dc;
  background: #ffffff;
}

.conflict-diff-head {
  position: sticky;
  top: 0;
  z-index: 1;
  padding: 8px 10px;
  border-bottom: 1px solid #c9d2dc;
  background: #edf1f5;
  font-weight: 700;
}

.conflict-diff-cell {
  display: grid;
  grid-template-columns: auto minmax(0, 1fr);
  gap: 6px;
  align-items: start;
  min-height: 26px;
  margin: 0;
  padding: 6px 10px;
  border-bottom: 1px solid #e2e8f0;
  white-space: pre-wrap;
  word-break: break-word;
}

.conflict-diff-cell button {
  min-width: 48px;
  padding: 4px 6px;
  font-size: 12px;
}

.conflict-diff-cell pre {
  margin: 0;
  white-space: pre-wrap;
}

.conflict-diff-cell span {
  display: inline-block;
  width: 36px;
  margin-right: 8px;
  color: #64748b;
  user-select: none;
}

.conflict-diff-cell.is-local {
  background: #fff3e8;
}

.conflict-diff-cell.is-external {
  background: #eaf6f0;
}

.merge-composition {
  display: grid;
  gap: 8px;
  padding: 10px;
  border: 1px solid #c9d2dc;
  background: #f8fafc;
}

.merge-composition header,
.merge-composition li {
  display: flex;
  align-items: center;
  gap: 8px;
}

.merge-composition header {
  justify-content: space-between;
}

.merge-composition ol {
  display: grid;
  gap: 6px;
  margin: 0;
  padding: 0;
  list-style: none;
}

.merge-composition li {
  padding: 6px;
  border: 1px solid #dbe3ec;
  background: #ffffff;
}

.merge-composition code {
  flex: 1;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.merge-composition button {
  padding: 4px 6px;
  font-size: 12px;
}

.merge-source {
  min-width: 74px;
  color: #475569;
  font-size: 12px;
  font-weight: 700;
  text-transform: capitalize;
}

.merge-editor {
  display: grid;
  gap: 6px;
}

.merge-editor textarea {
  min-height: 240px;
  resize: vertical;
  font-family: Menlo, Consolas, monospace;
}

@media (max-width: 900px) {
  .app-menu-bar {
    max-width: 52vw;
    overflow-x: auto;
  }

  .app-menu-panel {
    position: fixed;
    top: 38px;
    left: 8px;
  }

  .command-bar {
    max-height: none;
    overflow-y: visible;
  }

  .command-toolbar-row {
    overflow-x: auto;
    overflow-y: hidden;
    padding-bottom: 3px;
  }

  .command-group,
  .compact-field {
    max-width: 100%;
  }

  .command-agent-route,
  .command-agent-preview {
    grid-template-columns: 1fr;
